// ===================== SHARED PERSISTENCE =====================
const AB_BACKEND_ENDPOINT='/.netlify/functions/connect-db';
const AB_SYNC_STATUS_KEY='ab_sync_status_v1';
let abRemoteSyncInFlight=false;
let abRemoteUsersSyncInFlight=false;
let abSyncStatus={ mode:'local', ok:false, scope:'startup', message:'Using local browser storage until shared sync is available.', updatedAt:null };

function abUpdateSyncStatus(patch){
  abSyncStatus=Object.assign({}, abSyncStatus, patch||{}, { updatedAt:new Date().toISOString() });
  try{ localStorage.setItem(AB_SYNC_STATUS_KEY, JSON.stringify(abSyncStatus)); }catch(_){ }
  try{ window.dispatchEvent(new CustomEvent('ab:sync-status', { detail: abSyncStatus })); }catch(_){ }
  return abSyncStatus;
}
function abGetSyncStatus(){
  try{
    const stored=JSON.parse(localStorage.getItem(AB_SYNC_STATUS_KEY)||'null');
    if(stored && typeof stored==='object') abSyncStatus=Object.assign({}, abSyncStatus, stored);
  }catch(_){ }
  return abSyncStatus;
}
window.abGetSyncStatus = abGetSyncStatus;
window.abRefreshAdminSyncStatus = async function(){
  await Promise.allSettled([abSyncStateFromServer(), abSyncUsersFromServer()]);
  return abGetSyncStatus();
};
abUpdateSyncStatus({ mode:'local', ok:false, scope:'startup', message:'Using local browser storage until shared sync is available.' });

function abClone(v){ return JSON.parse(JSON.stringify(v)); }
function abBuildStateSnapshot(){
  return { countries, cities, tips, settings, countryPages, cityPages, ads, cityItems };
}
function abApplyStateSnapshot(snapshot, persistLocal=true){
  if(!snapshot || typeof snapshot!=='object') return false;
  countries=Array.isArray(snapshot.countries)&&snapshot.countries.length? snapshot.countries : abClone(DEFAULT_COUNTRIES);
  cities=Array.isArray(snapshot.cities)&&snapshot.cities.length? snapshot.cities : abClone(DEFAULT_CITIES);
  tips=Array.isArray(snapshot.tips)&&snapshot.tips.length? snapshot.tips : abClone(DEFAULT_TIPS);
  settings=snapshot.settings&&typeof snapshot.settings==='object' ? snapshot.settings : abClone(DEFAULT_SETTINGS);
  countryPages=snapshot.countryPages&&typeof snapshot.countryPages==='object' ? snapshot.countryPages : {};
  cityPages=snapshot.cityPages&&typeof snapshot.cityPages==='object' ? snapshot.cityPages : {};
  ads=Array.isArray(snapshot.ads)&&snapshot.ads.length? snapshot.ads : abClone(DEFAULT_ADS);
  cityItems=Array.isArray(snapshot.cityItems)&&snapshot.cityItems.length? snapshot.cityItems : abClone(DEFAULT_CITY_ITEMS);
  if(persistLocal){
    localStorage.setItem('ab_countries',JSON.stringify(countries));
    localStorage.setItem('ab_cities',JSON.stringify(cities));
    localStorage.setItem('ab_countryPages',JSON.stringify(countryPages));
    localStorage.setItem('ab_cityPages',JSON.stringify(cityPages));
    localStorage.setItem('ab_cityItems',JSON.stringify(cityItems));
    localStorage.setItem('ab_tips',JSON.stringify(tips));
    localStorage.setItem('ab_ads',JSON.stringify(ads));
    localStorage.setItem('ab_settings',JSON.stringify(settings));
  }
  return true;
}
async function abBackendRequest(action, payload){
  const res=await fetch(AB_BACKEND_ENDPOINT,{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({action,payload})
  });
  const data=await res.json().catch(()=>({}));
  if(!res.ok) throw new Error(data.error || ('Request failed: '+res.status));
  return data;
}
async function abSyncStateFromServer(){
  if(abRemoteSyncInFlight) return;
  abRemoteSyncInFlight=true;
  try{
    const data=await abBackendRequest('getState',{});
    if(data && data.state){
      abApplyStateSnapshot(data.state,true);
      migrateFeaturedPinsToEntityOrder();
      renderHome();
      if(typeof apInitAll==='function' && document.getElementById('admin-page')) apInitAll();
      abUpdateSyncStatus({ mode:'neon', ok:true, scope:'state', message:'Connected to shared Neon data.' });
    }else{
      abUpdateSyncStatus({ mode:'neon', ok:true, scope:'state', message:'Connected to Neon. No shared site state found yet.' });
    }
  }catch(err){
    console.warn('Shared state sync skipped:', err.message || err);
    abUpdateSyncStatus({ mode:'local', ok:false, scope:'state', message:'Shared sync unavailable. Using local browser data.', error:String(err && err.message || err || '') });
  }finally{
    abRemoteSyncInFlight=false;
  }
}
let abSaveStateTimer=null;
function abQueueRemoteStateSave(){
  clearTimeout(abSaveStateTimer);
  abSaveStateTimer=setTimeout(async ()=>{
    try{
      await abBackendRequest('saveState',{ state: abBuildStateSnapshot() });
      abUpdateSyncStatus({ mode:'neon', ok:true, scope:'state-save', message:'Changes saved to shared Neon data.' });
    }catch(err){
      console.warn('Shared state save skipped:', err.message || err);
      abUpdateSyncStatus({ mode:'local', ok:false, scope:'state-save', message:'Could not save to Neon. Changes are only in this browser for now.', error:String(err && err.message || err || '') });
    }
  },250);
}
async function abSyncUsersFromServer(){
  if(abRemoteUsersSyncInFlight) return;
  abRemoteUsersSyncInFlight=true;
  try{
    const data=await abBackendRequest('getUsers',{});
    if(Array.isArray(data.users)){
      localStorage.setItem(AB_USERS_KEY, JSON.stringify(data.users));
      abUpdateSyncStatus({ mode:'neon', ok:true, scope:'users', message:'Connected to shared Neon data.' });
      const current=safeJsonParse(localStorage.getItem(AB_CURRENT_USER_KEY), null);
      if(current && current.email){
        const fresh=data.users.find(u=>String(u.email||'').toLowerCase()===String(current.email||'').toLowerCase());
        if(fresh) localStorage.setItem(AB_CURRENT_USER_KEY, JSON.stringify(fresh));
      }
      updateFloatingAccountButton();
    }
  }catch(err){
    console.warn('Shared users sync skipped:', err.message || err);
    abUpdateSyncStatus({ mode:'local', ok:false, scope:'users', message:'Shared user sync unavailable. Using local browser accounts.', error:String(err && err.message || err || '') });
  }finally{
    abRemoteUsersSyncInFlight=false;
  }
}
let abSaveUsersTimer=null;
function abQueueRemoteUsersSave(users){
  clearTimeout(abSaveUsersTimer);
  abSaveUsersTimer=setTimeout(async ()=>{
    try{
      await abBackendRequest('saveUsers',{ users });
      abUpdateSyncStatus({ mode:'neon', ok:true, scope:'users-save', message:'Users saved to shared Neon data.' });
    }catch(err){
      console.warn('Shared users save skipped:', err.message || err);
      abUpdateSyncStatus({ mode:'local', ok:false, scope:'users-save', message:'Could not save users to Neon. This browser is using local-only auth data.', error:String(err && err.message || err || '') });
    }
  },250);
}

// ===================== STATE =====================
let countries,cities,tips,settings,countryPages,cityPages,ads,cityItems,currentCountryId=null,currentCityId=null,currentCatKey=null,loggedIn=false;

function loadData(){
  countries=JSON.parse(localStorage.getItem('ab_countries')||'null')||JSON.parse(JSON.stringify(DEFAULT_COUNTRIES));
  cities=JSON.parse(localStorage.getItem('ab_cities')||'null')||JSON.parse(JSON.stringify(DEFAULT_CITIES));
  tips=JSON.parse(localStorage.getItem('ab_tips')||'null')||JSON.parse(JSON.stringify(DEFAULT_TIPS));
  settings=JSON.parse(localStorage.getItem('ab_settings')||'null')||JSON.parse(JSON.stringify(DEFAULT_SETTINGS));
  cityPages=JSON.parse(localStorage.getItem('ab_cityPages')||localStorage.getItem('ab_citypages')||'{}');
  countryPages=JSON.parse(localStorage.getItem('ab_countryPages')||'{}');
  const storedItems=JSON.parse(localStorage.getItem('ab_cityItems')||localStorage.getItem('ab_cityitems')||'null');
  cityItems=storedItems&&storedItems.length>0?storedItems:JSON.parse(JSON.stringify(DEFAULT_CITY_ITEMS));
  loadAds();
}
function saveAll(){
  try{
    localStorage.setItem('ab_countries',JSON.stringify(countries));
    localStorage.setItem('ab_cities',JSON.stringify(cities));
    localStorage.setItem('ab_countryPages',JSON.stringify(countryPages));
    localStorage.setItem('ab_cityPages',JSON.stringify(cityPages));
    localStorage.setItem('ab_cityItems',JSON.stringify(cityItems));
    localStorage.setItem('ab_tips',JSON.stringify(tips));
    localStorage.setItem('ab_ads',JSON.stringify(ads));
    localStorage.setItem('ab_settings',JSON.stringify(settings));
    abQueueRemoteStateSave();
  }catch(err){
    console.error(err);
    if(err && (err.name === 'QuotaExceededError' || String(err).includes('QuotaExceeded'))){
      alert('Storage quota exceeded. This usually means an older base64 image is still saved locally. Re-upload affected images through Cloudinary so only URLs are stored.');
      return;
    }
    throw err;
  }
}

function migrateFeaturedPinsToEntityOrder(){
  try{
    const legacyRaw=localStorage.getItem('ab_featured');
    if(!legacyRaw) return;
    const legacy=JSON.parse(legacyRaw||'{}')||{};
    let changed=false;
    (legacy.cities||[]).forEach((id,idx)=>{
      const city=(cities||[]).find(c=>c.id===id);
      if(city && (city.featuredOrder===undefined || city.featuredOrder===null || city.featuredOrder==='')){
        city.featuredOrder=idx+1;
        changed=true;
      }
    });
    ['restaurants','attractions','offers'].forEach(cat=>{
      (legacy[cat]||[]).forEach((id,idx)=>{
        const item=(cityItems||[]).find(i=>i.id===id);
        if(item && item.category===cat && (item.featuredOrder===undefined || item.featuredOrder===null || item.featuredOrder==='')){
          item.featuredOrder=idx+1;
          changed=true;
        }
      });
    });
    if(changed) saveAll();
    localStorage.removeItem('ab_featured');
  }catch(err){
    console.warn('Featured migration skipped', err);
  }
}
function uid(){return Date.now().toString(36)+Math.random().toString(36).slice(2,6)}

// ===================== RENDER =====================
function renderHome(){
  applySettings();
  renderCountries();
  renderTips();
  renderFeaturedCarousels();
}
function adCardHtml(ad){
  return`<div class="tip-card ad-card" style="background:${ad.bg};" onclick="window.open('${ad.link}','_blank')">
    ${ad.image?`<img src="${ad.image}" alt="${ad.title}">`:''}
    <h3>${ad.title}</h3>
    <a href="${ad.link}" class="ad-cta" target="_blank" onclick="event.stopPropagation()">${ad.cta}</a>
  </div>`;
}
function insertAdsAt(items, locationKey){
  // Parse location string e.g. 'tips-after-2' → insert after index 2
  const match = locationKey.match(/after-(\d+)$/);
  const insertAfter = match ? parseInt(match[1]) : items.length;
  const adsHere = ads.filter(a => a.location === locationKey).map(adCardHtml).join('');
  if(!adsHere) return items;
  const before = items.slice(0, insertAfter);
  const after = items.slice(insertAfter);
  return [...before, adsHere, ...after];
}
function applySettings(){
  const h=document.querySelector('.hero-title');
  if(h)h.innerHTML=`${settings.hero1}<br><em>${settings.hero2}</em>`;
  const hs=document.querySelector('.hero-sub');
  if(hs)hs.textContent=settings.herosub;
  const stats=document.querySelectorAll('.hero-stat');
  if(stats.length>=3){
    stats[0].innerHTML=`<strong>${settings.stat1n}</strong><span>${settings.stat1l}</span>`;
    stats[1].innerHTML=`<strong>${settings.stat2n}</strong><span>${settings.stat2l}</span>`;
    stats[2].innerHTML=`<strong>${settings.stat3n}</strong><span>${settings.stat3l}</span>`;
  }
  // CTA buttons
  const cta1=document.getElementById('hero-cta1');
  if(cta1){
    const lbl=settings.cta1label||'Explore Destinations';
    const link=settings.cta1link||'#countries';
    cta1.textContent=lbl;
    if(link.startsWith('#')){
      cta1.href='javascript:void(0)';
      cta1.onclick=function(){const el=document.getElementById(link.slice(1));if(el)el.scrollIntoView({behavior:'smooth'});};
    }else{
      cta1.href=link;cta1.target='_blank';cta1.onclick=null;
    }
    cta1.style.display=lbl?'':'none';
  }
  const cta2=document.getElementById('hero-cta2');
  if(cta2){
    const lbl2=settings.cta2label||'';
    const link2=settings.cta2link||'';
    cta2.textContent=lbl2;
    if(lbl2&&link2){
      cta2.style.display='';
      if(link2.startsWith('#')){
        cta2.href='javascript:void(0)';
        cta2.onclick=function(){const el=document.getElementById(link2.slice(1));if(el)el.scrollIntoView({behavior:'smooth'});};
      }else{
        cta2.href=link2;cta2.target='_blank';cta2.onclick=null;
      }
    }else{cta2.style.display='none';}
  }
}
function renderCountries(){
  const g=document.getElementById('countries-grid');
  if(!g)return;
  let items=countries.map(c=>{
    return`<div class="country-card" onclick="openCountry('${c.id}')">
      ${c.featured=='1'?'<div class="country-badge">✦</div>':''}
      <span class="country-flag-large">${c.flag}</span>
      <div class="country-body">
        <h3 class="country-name">${c.name}</h3>
        <div class="country-meta">
          ${c.season?`<span>📅 ${c.season}</span>`:''}
          ${c.currency?`<span>💰 ${c.currency}</span>`:''}
        </div>
      </div>
    </div>`;
  });
  items = insertAdsAt(items, 'countries-after-3');
  g.innerHTML = items.join('');
}
function renderTips(){
  const g=document.getElementById('tips-grid');
  if(!g)return;
  let items=tips.map(t=>`
    <div class="tip-card">
      <div class="tip-icon">${t.icon}</div>
      <h3>${t.title}</h3>
      <p>${t.content}</p>
    </div>`);
  items = insertAdsAt(items, 'tips-after-2');
  items = insertAdsAt(items, 'tips-after-4');
  g.innerHTML = items.join('');
}

// ===================== FEATURED CAROUSELS =====================

function renderFeaturedCarousels(){
  renderFeaturedCities();
  renderFeaturedCategory('restaurants','restaurants-track');
  renderFeaturedCategory('attractions','attractions-track');
  renderFeaturedCategory('offers','offers-track');
  initCarouselDrag();
}

function renderFeaturedCities(){
  const track=document.getElementById('cities-track');
  if(!track)return;
  const ordered=(cities||[])
    .filter(c=>Number.isFinite(Number(c.featuredOrder)) && Number(c.featuredOrder)>0)
    .sort((a,b)=>Number(a.featuredOrder)-Number(b.featuredOrder) || a.name.localeCompare(b.name));
  const featuredCities=(ordered.length?ordered:(cities||[]).slice()).slice(0,14);
  if(!featuredCities.length){
    track.innerHTML=`<div class="fc-empty">No cities added yet — add some in the Admin Panel.</div>`;
    return;
  }
  track.innerHTML=featuredCities.map(city=>{
    const country=countries.find(c=>c.id===city.countryId);
    const img=city.heroImage||'';
    const bg=img?`background-image:url('${img}')`:`background:linear-gradient(135deg,${city.gradient||'#c85a3c,#c9a84c'})`;
    return`<div class="fc-card" onclick="openCity('${city.id}')">
      <div class="fc-img" style="${bg}">
        ${!img?`<span style="position:relative;z-index:2;filter:drop-shadow(0 4px 12px rgba(0,0,0,.5))">${city.icon||'🏙'}</span>`:''}
        <div class="fc-img-overlay"></div>
        ${country?`<div class="fc-badge">${country.flag} ${country.name}</div>`:''}
      </div>
      <div class="fc-body">
        <div class="fc-name">${city.name}</div>
        <div class="fc-meta">${country?country.flag+' '+country.name:''}${city.bestFor?' · '+city.bestFor:''}</div>
      </div>
    </div>`;
  }).join('');
}

function renderFeaturedCategory(category, trackId){
  const track=document.getElementById(trackId);
  if(!track)return;
  const CAT=CAT_META[category]||{icon:'📌',label:category,bg:'linear-gradient(135deg,#888,#aaa)'};
  const pool=(cityItems||[]).filter(i=>i.category===category);
  const ordered=pool
    .filter(i=>Number.isFinite(Number(i.featuredOrder)) && Number(i.featuredOrder)>0)
    .sort((a,b)=>Number(a.featuredOrder)-Number(b.featuredOrder) || a.name.localeCompare(b.name));
  const items=(ordered.length?ordered:pool).slice(0,14);
  if(!items.length){
    track.innerHTML=`<div class="fc-empty">No ${CAT.label.toLowerCase()} added yet — add some in the Admin Panel under City Items.</div>`;
    return;
  }
  track.innerHTML=items.map(item=>{
    const city=cities.find(c=>c.id===item.cityId);
    const country=city?countries.find(c=>c.id===city.countryId):null;
    const img=item.image||'';
    const bg=img?`background-image:url('${img}')`:CAT.bg;
    const isOffer=category==='offers';
    return`<div class="fc-card${category==='restaurants'?' restaurant':''}" onclick="openCity('${item.cityId}');setTimeout(()=>{openCatListing('${item.cityId}','${category}');setTimeout(()=>openItemDetail('${item.id}'),300)},300)">
      <div class="fc-img" style="${bg}">
        ${!img?`<span style="position:relative;z-index:2;font-size:2.8rem;filter:drop-shadow(0 4px 12px rgba(0,0,0,.5))">${item.icon||CAT.icon}</span>`:''}
        <div class="fc-img-overlay"></div>
        ${city?`<div class="fc-badge">${city.icon||'🏙'} ${city.name}</div>`:''}
        ${item.rating?`<div class="fc-rating">⭐ ${item.rating}</div>`:''}
      </div>
      <div class="fc-body">
        <div class="fc-name">${item.name}</div>
        <div class="fc-meta">${country?country.flag+' '+country.name:''}${item.address?' · '+item.address:''}</div>
        ${item.price?`<div class="fc-price">${isOffer?'🏷️ ':'💰 '}${item.price}</div>`:''}
      </div>
    </div>`;
  }).join('');
}

function carouselScroll(trackId, direction){
  const outer=document.getElementById(trackId+'-outer');
  if(!outer)return;
  const scrollAmount=outer.clientWidth*0.7;
  outer.scrollBy({left:direction*scrollAmount,behavior:'smooth'});
}

function initCarouselDrag(){
  document.querySelectorAll('.carousel-track-outer').forEach(outer=>{
    let isDown=false,startX=0,scrollLeft=0;
    outer.addEventListener('mousedown',e=>{isDown=true;outer.classList.add('dragging');startX=e.pageX-outer.offsetLeft;scrollLeft=outer.scrollLeft;});
    outer.addEventListener('mouseleave',()=>{isDown=false;outer.classList.remove('dragging');});
    outer.addEventListener('mouseup',()=>{isDown=false;outer.classList.remove('dragging');});
    outer.addEventListener('mousemove',e=>{if(!isDown)return;e.preventDefault();const x=e.pageX-outer.offsetLeft;outer.scrollLeft=scrollLeft-(x-startX)*1.2;});
  });
}

function openSearchWithCategory(cat){
  openSearch();
  setTimeout(()=>{
    const dd=document.getElementById('sd-category');
    if(dd){dd.value=cat;onSdCategory();}
  },100);
}

// ===================== COUNTRY PAGE =====================
function openCountry(id){
  const c=countries.find(x=>x.id===id);
  if(!c)return;
  currentCountryId=id;
  document.getElementById('cp-flag').textContent=c.flag;
  document.getElementById('cp-name').textContent=c.name;
  const ch=document.getElementById('country-hero-section');
  const chBg=document.getElementById('country-hero-bg');
  const pastelPalette=['#FDE8E8','#E8F1FD','#F3E8FD','#E6F7F1','#FFF4E5','#FFEAF0','#EAF7EA','#E8F7FA','#E8F0FE','#FFF7E8','#FFF0E6'];
  const paletteIndex=Math.abs(Array.from(id).reduce((acc,char)=>acc+char.charCodeAt(0),0))%pastelPalette.length;
  const pastel=pastelPalette[paletteIndex];
  if(ch) ch.style.setProperty('--country-hero-pastel',pastel);
  const cpImg=c.heroImage||c.pageHeroImage||'';
  if(chBg){
    chBg.classList.remove('country-hero-fallback','has-image');
    if(cpImg){
      chBg.innerHTML='';
      chBg.style.backgroundImage=`url('${cpImg}')`;
      chBg.style.backgroundColor='rgba(255,255,255,.35)';
      chBg.classList.add('has-image');
    } else {
      chBg.style.backgroundImage='none';
      chBg.style.backgroundColor='transparent';
      chBg.style.background=`linear-gradient(135deg,${c.gradient||'#f5f0e8,#e8f7fa'})`;
      chBg.innerHTML=`<span>${c.flag||'🌍'}</span>`;
      chBg.classList.add('country-hero-fallback');
    }
  }
  // Use pageTagline if set
  document.getElementById('cp-tagline').textContent=c.pageTagline||c.desc||'';
  const heroMeta=document.getElementById('cp-hero-meta');
  if(heroMeta){
    const countryCities=cities.filter(x=>x.countryId===id);
    const heroMetas=[];
    if(countryCities.length) heroMetas.push(`<span>${countryCities.length} ${countryCities.length===1?'city':'cities'}</span>`);
    if(c.currency) heroMetas.push(`<span>${c.currency}</span>`);
    if(c.language) heroMetas.push(`<span>${c.language}</span>`);
    heroMeta.innerHTML=heroMetas.join('');
    heroMeta.style.display=heroMetas.length?'flex':'none';
  }
  // About section
  const aboutSec=document.getElementById('cp-about-section');
  if(aboutSec){
    const hasAbout=c.pageAbout||c.currency||c.language;
    aboutSec.style.display=hasAbout?'':'none';
    const aboutEl=document.getElementById('cp-about-text');
    if(aboutEl)aboutEl.textContent=c.pageAbout||'';
    const metaRow=document.getElementById('cp-meta-row');
    if(metaRow){
      const metas=[];
      if(c.currency)metas.push(`<span style="font-size:.82rem;color:rgba(13,13,13,.55)">💰 <strong>Currency:</strong> ${c.currency}</span>`);
      if(c.language)metas.push(`<span style="font-size:.82rem;color:rgba(13,13,13,.55)">🗣 <strong>Language:</strong> ${c.language}</span>`);
      metaRow.innerHTML=metas.join('');
    }
  }
  document.getElementById('cp-cities-title').textContent=`Top Cities & Destinations in ${c.name}`;
  document.getElementById('cp-cities-sub').textContent=`Discover the most captivating places across ${c.name}.`;
  const citiesForCountry=cities.filter(x=>x.countryId===id);
  const cg=document.getElementById('cities-grid');
  if(citiesForCountry.length){
    let cityItems=citiesForCountry.map(city=>{
      const highlights=(city.highlights||'').split(',').filter(Boolean).map(h=>`<span class="highlight-tag">${h.trim()}</span>`).join('');
      const heroImgHtml=city.heroImage
        ?`<div style="width:100%;height:190px;background:url('${city.heroImage}') center/cover no-repeat;position:relative">
             <div style="position:absolute;inset:0;background:linear-gradient(to top,rgba(13,13,13,.35),transparent)"></div>
           </div>`
        :`<div class="city-img" style="background:linear-gradient(135deg,${city.gradient||'#c85a3c,#c9a84c'})">
             <span style="font-size:3rem;position:relative;z-index:1">${city.icon||'🏙️'}</span>
           </div>`;
      return`<div class="city-card" style="cursor:pointer" onclick="openCity('${city.id}')">
        ${heroImgHtml}
        <div class="city-body">
          <h3 class="city-name">${city.name}</h3>
          <p class="city-desc">${city.desc}</p>
          ${highlights?`<div class="city-highlights">${highlights}</div>`:''}
          ${city.bestFor?`<p style="font-size:.78rem;color:rgba(13,13,13,.45);margin-bottom:12px">✦ Best for: <strong>${city.bestFor}</strong></p>`:''}
          <button class="cta-btn" style="margin-top:4px">
            Explore ${city.name}
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
          </button>
        </div>
      </div>`;
    });
    cityItems = insertAdsAt(cityItems, 'cities-after-2');
    cg.innerHTML = cityItems.join('');
  } else {
    cg.innerHTML=`<p style="color:rgba(13,13,13,.4);grid-column:1/-1">No destinations added yet for this country. Add some in the Admin Panel.</p>`;
  }
  hideHomeSections();
  const cp=document.getElementById('country-page');
  if(cp) cp.style.display='block';
  safeScrollTop();
}

// ===================== CITY CATS HUB =====================
const CAT_META = {
  'restaurants':    {icon:'🍽', label:'Restaurants',    bg:'linear-gradient(135deg,#c85a3c,#c9a84c)', desc:'Dining & drinks',       sampleImage:'data:image/jpeg;base64,'},
  'attractions':    {icon:'🏛', label:'Attractions',    bg:'linear-gradient(135deg,#2d5f8a,#4a7c6a)', desc:'Sights & landmarks',    sampleImage:'data:image/jpeg;base64,'},
  'activities':     {icon:'🎯', label:'Activities',     bg:'linear-gradient(135deg,#4a7c6a,#2d5f8a)', desc:'Things to do',          sampleImage:'data:image/jpeg;base64,'},
  'important-links':{icon:'📍', label:'Travel Deeper',  bg:'linear-gradient(135deg,#c85a3c,#2d5f8a)', desc:'Go beyond the surface', sampleImage:'data:image/jpeg;base64,'},
  'getting-around': {icon:'🚇', label:'Getting Around', bg:'linear-gradient(135deg,#0d0d0d,#2d5f8a)', desc:'Transport & navigation', sampleImage:'data:image/jpeg;base64,'},
  'shopping':       {icon:'🛍', label:'Shopping',       bg:'linear-gradient(135deg,#c9a84c,#c85a3c)', desc:'Markets & stores',      sampleImage:'data:image/jpeg;base64,'},
  'hotels':         {icon:'🏨', label:'Hotels',         bg:'linear-gradient(135deg,#2d5f8a,#0d0d0d)', desc:'Stay & accommodation',  sampleImage:'data:image/jpeg;base64,'},
  'local-cuisine':  {icon:'🥘', label:'Local Cuisine',  bg:'linear-gradient(135deg,#8b4513,#c9a84c)', desc:'Traditional & local food', sampleImage:'data:image/jpeg;base64,'},
  'events':         {icon:'🎉', label:'Events',          bg:'linear-gradient(135deg,#6a0dad,#c85a3c)', desc:'Festivals & events',    sampleImage:'data:image/jpeg;base64,'},
  'offers':         {icon:'🏷️', label:'Offers',          bg:'linear-gradient(135deg,#2d8a3c,#c9a84c)', desc:'Deals & discounts',     sampleImage:'data:image/jpeg;base64,'},
};

function openCity(cityId){
  const city=cities.find(x=>x.id===cityId);
  if(!city)return;
  currentCityId=cityId;

  // Pastel palette — one chosen deterministically per city so it's stable
  const PASTELS=[
    '#FDE8E8','#E8F1FD','#F3E8FD','#E6F7F1',
    '#FFF4E5','#FFEAF0','#EAF7EA','#E8F7FA',
    '#E8F0FE','#FFF7E8','#FFF0E6','#EAF3DE',
    '#FAEEDA','#E1F5EE','#FAECE7','#FBEAF0'
  ];
  // pick deterministically by hashing city id
  const pastelIdx=[...cityId].reduce((a,c)=>a+c.charCodeAt(0),0)%PASTELS.length;
  const pastel=PASTELS[pastelIdx];

  const heroEl=document.getElementById('city-cats-hero');
  const imgEl=document.getElementById('city-cats-img');

  if(heroEl) heroEl.style.background=pastel;

  // City image = tile image = carousel image (heroImage)
  const img=city.heroImage||'';
  if(imgEl){
    if(img){
      imgEl.innerHTML='';
      imgEl.style.backgroundImage=`url('${img}')`;
      imgEl.style.background=`url('${img}') center/cover no-repeat`;
    } else {
      imgEl.style.backgroundImage='none';
      imgEl.style.background=`linear-gradient(135deg,${city.gradient||'#c85a3c,#c9a84c'})`;
      imgEl.innerHTML='';
    }
  }

  const iconEl=document.getElementById('city-cats-icon');
  if(iconEl) iconEl.textContent=city.icon||'🏙️';
  document.getElementById('city-cats-title').textContent=city.name;
  const country=countries.find(x=>x.id===city.countryId);
  const metaParts=[];
  if(city.bestFor)metaParts.push(`✦ ${city.bestFor}`);
  if(country)metaParts.push(`${country.flag} ${country.name}`);
  document.getElementById('city-cats-meta').innerHTML=metaParts.map(m=>`<span>${m}</span>`).join('');

  const CAT_CARD_ICONS = {
    restaurants:'🍽️',
    attractions:'🏛️',
    activities:'🎯',
    'getting-around':'🚇',
    shopping:'🛍️',
    hotels:'🏨',
    'important-links':'📍',
    'local-cuisine':'🥘',
    events:'🎉',
    offers:'🏷️',
    destinations:'📍'
  };

  const grid=document.getElementById('city-cats-grid');
  grid.innerHTML=Object.entries(CAT_META).map(([key,cat])=>{
    const count=(cityItems||[]).filter(i=>i.cityId===cityId&&i.category===key).length;
    const icon=(cat.icon||CAT_CARD_ICONS[key]||'✨');
    return `<div class="city-cat-card cat-${key}" data-city-id="${cityId}" data-cat-key="${key}" role="button" tabindex="0" aria-label="Open ${cat.label} in ${city.name}">
      <div class="city-cat-card-body">
        <div class="city-cat-card-icon">${icon}</div>
        <div class="city-cat-card-name">${cat.label}</div>
        <div class="city-cat-card-count">${count} item${count!==1?'s':''}</div>
      </div>
    </div>`;
  }).join('');

  const aboutTitle=document.getElementById('city-about-title');
  const aboutText=document.getElementById('city-about-text');
  if(aboutTitle) aboutTitle.textContent=`About ${city.name}`;
  if(aboutText){
    const summary = city.pageAbout || city.longDesc || city.desc || city.bestFor || 'Explore the local character, signature experiences, practical tips, and the best reasons to visit this destination.';
    aboutText.textContent = summary;
  }

  hideHomeSections();
  document.getElementById('country-page').style.display='none';
  document.getElementById('item-detail').style.display='none';
  document.getElementById('cat-listing').style.display='none';
  const tipsEl=document.getElementById('tips');if(tipsEl)tipsEl.style.display='none';
  document.getElementById('city-cats').style.display='block';
  safeScrollTop();
}

function openCatListing(cityId, catKey){
  const city=cities.find(x=>x.id===cityId);
  if(!city)return;
  currentCityId=cityId;
  currentCatKey=catKey;
  const cat=CAT_META[catKey];
  const items=(cityItems||[]).filter(i=>i.cityId===cityId&&i.category===catKey);
  // Hero
  const hero=document.getElementById('cat-listing-hero');
  const heroBg=document.getElementById('cat-listing-hero-bg');
  if(hero) hero.style.setProperty('--cat-hero-pastel',cat.bg||'#FDE8E8');
  if(heroBg){
    heroBg.classList.remove('cat-listing-fallback','has-image');
    const featuredItem=items.find(i=>i.image);
    const heroImg=city.heroImage||city.pageHeroImage||(featuredItem&&featuredItem.image)||'';
    if(heroImg){
      heroBg.innerHTML='';
      heroBg.style.backgroundImage=`url('${heroImg}')`;
      heroBg.style.backgroundColor='rgba(255,255,255,.35)';
      heroBg.classList.add('has-image');
    } else {
      heroBg.style.backgroundImage='none';
      heroBg.style.backgroundColor='transparent';
      heroBg.style.background=cat.bg||'linear-gradient(135deg,#FDE8E8,#FFF4E5)';
      heroBg.innerHTML=`<span>${cat.icon||'🍽️'}</span>`;
      heroBg.classList.add('cat-listing-fallback');
    }
  }
  document.getElementById('cat-listing-icon').textContent=cat.icon;
  document.getElementById('cat-listing-title').textContent=`${cat.label} in ${city.name}`;
  document.getElementById('cat-listing-sub').textContent=cat.desc;
  const heroMeta=document.getElementById('cat-listing-meta');
  if(heroMeta){
    const metas=[];
    if(items.length) metas.push(`<span>${items.length} ${items.length===1?cat.label.slice(0,-1).toLowerCase():cat.label.toLowerCase()}</span>`);
    if(city.countryId){
      const country=countries.find(x=>x.id===city.countryId);
      if(country&&country.name) metas.push(`<span>${country.name}</span>`);
    }
    if(city.bestFor) metas.push(`<span>${city.bestFor}</span>`);
    heroMeta.innerHTML=metas.join('');
    heroMeta.style.display=metas.length?'flex':'none';
  }
  // Items grid
  const grid=document.getElementById('cat-listing-grid');
  if(items.length){
    grid.innerHTML=items.map(item=>{
      const tags=(item.tags||'').split(',').filter(Boolean).map(t=>`<span class="cat-tile-tag">${t.trim()}</span>`).join('');
      const imgStyle=item.image?`background-image:url('${item.image}');background-color:#eee`:`background:${cat.bg}`;
      // Special badges for events, offers, important-links
      const eventBadge=item.category==='events'&&item.openingHours?`<div class="cat-tile-event-date">📅 ${item.openingHours}</div>`:'';
      const offerBadge=item.category==='offers'&&item.price?`<div class="cat-tile-offer-badge">🏷️ ${item.price}</div>`:'';
      const isLink=item.category==='important-links';
      const ctaBtn=isLink&&item.website
        ?`<a class="cat-tile-link-btn" href="${item.website}" target="_blank" rel="noopener">🔗 Visit Link</a>`
        :`<button class="cat-tile-cta" onclick="openItemDetail('${item.id}')">
            ${isLink?'View Details':item.category==='offers'?'See Offer':item.category==='events'?'Event Info':'View Details'}
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
          </button>`;
      return`<div class="cat-tile">
        <div class="cat-tile-img" style="${imgStyle}">
          ${!item.image?`<span style="position:relative;z-index:2;font-size:5rem;line-height:1;filter:drop-shadow(0 4px 12px rgba(13,13,13,.4))">${item.icon||cat.icon}</span>`:''}
          <div class="cat-tile-img-overlay"></div>
        </div>
        <div class="cat-tile-body">
          ${eventBadge}${offerBadge}
          <div class="cat-tile-name">${item.name}</div>
          <p class="cat-tile-desc">${item.desc||''}</p>
          ${tags?`<div class="cat-tile-tags">${tags}</div>`:''}
          <div class="cat-tile-meta">
            ${item.price&&item.category!=='offers'?`<span>💰 ${item.price}</span>`:''}
            ${item.rating?`<span>⭐ ${item.rating}</span>`:''}
            ${item.address?`<span>📍 ${item.address}</span>`:''}
          </div>
          ${ctaBtn}
        </div>
      </div>`;
    }).join('');
  } else {
    grid.innerHTML=`<p style="color:rgba(13,13,13,.4);grid-column:1/-1;font-size:.95rem">No ${cat.label.toLowerCase()} added yet for ${city.name}. Add some in the Admin Panel under City Items.</p>`;
  }
  // Category-level map actions: open a Google Maps search instead of embedding a paid map
  const mapSection=document.getElementById('cat-map-section');
  const mapActions=document.getElementById('cat-map-actions');
  if(mapSection&&mapActions){
    const itemsWithCoords=items.filter(i=>i.mapCoords||i.address);
    if(itemsWithCoords.length>0){
      const q=city.name+' '+cat.label;
      const searchUrl=getGoogleMapsSearchUrl(q);
      mapActions.innerHTML=`<a class="item-detail-cta outline" href="${searchUrl}" target="_blank" rel="noopener">📍 View ${cat.label} in Google Maps</a>`;
      mapSection.style.display='block';
    } else {
      mapSection.style.display='none';
      mapActions.innerHTML='';
    }
  }
  document.getElementById('city-cats').style.display='none';
  const tipsEl=document.getElementById('tips');if(tipsEl)tipsEl.style.display='none';
  document.getElementById('cat-listing').style.display='block';
  window.scrollTo({top:0,behavior:'smooth'});
}

function showCityCats(){
  document.getElementById('cat-listing').style.display='none';
  document.getElementById('item-detail').style.display='none';
  document.getElementById('city-cats').style.display='block';
  const tipsEl=document.getElementById('tips');if(tipsEl)tipsEl.style.display='none';
  window.scrollTo({top:0,behavior:'smooth'});
}


function hideHomeSections(){
  ['hero','countries','main-footer','tips','featured-cities-section','featured-restaurants-section','featured-attractions-section','featured-offers-section'].forEach(id=>{
    const el=document.getElementById(id);
    if(el) el.style.display='none';
  });
}
function safeScrollTop(){
  window.scrollTo({top:0,behavior:'smooth'});
  setTimeout(()=>window.scrollTo(0,0),220);
}

function showCatListing(){
  hideHomeSections();
  document.getElementById('country-page').style.display='none';
  document.getElementById('city-cats').style.display='none';
  document.getElementById('item-detail').style.display='none';
  document.getElementById('cat-listing').style.display='block';
  const tipsEl=document.getElementById('tips');if(tipsEl)tipsEl.style.display='none';
  safeScrollTop();
}

function openItemDetail(itemId){
  const item=(cityItems||[]).find(x=>x.id===itemId);
  if(!item)return;
  const cat=CAT_META[item.category]||{icon:'📌',label:item.category,bg:'linear-gradient(135deg,#888,#aaa)'};

  // ── Pastel hero (same palette as city/country heroes) ──────────────────
  const PASTELS=[
    '#FDE8E8','#E8F1FD','#F3E8FD','#E6F7F1',
    '#FFF4E5','#FFEAF0','#EAF7EA','#E8F7FA',
    '#E8F0FE','#FFF7E8','#FFF0E6','#EAF3DE',
    '#FAEEDA','#E1F5EE','#FAECE7','#FBEAF0'
  ];
  // deterministic pastel from item id
  const pastelIdx=[...item.id].reduce((a,c)=>a+c.charCodeAt(0),0)%PASTELS.length;
  const pastel=PASTELS[pastelIdx];

  const heroEl=document.getElementById('item-detail-hero');
  const heroBg=document.getElementById('item-detail-hero-bg');

  // Set pastel background on the card
  heroEl.style.setProperty('--item-hero-pastel', pastel);

  // Right-side inset image: prefer item image, else fallback emoji
  heroBg.classList.remove('has-image','id-hero-fallback');
  heroBg.innerHTML='';
  const heroImg=item.image||item.pageHeroImage||'';
  if(heroImg){
    heroBg.style.backgroundImage=`url('${heroImg}')`;
    heroBg.style.background=`url('${heroImg}') center/cover no-repeat`;
    heroBg.classList.add('has-image');
  } else {
    heroBg.style.backgroundImage='none';
    heroBg.style.background='rgba(255,255,255,.35)';
    heroBg.classList.add('id-hero-fallback');
    heroBg.innerHTML=`<span>${item.icon||cat.icon}</span>`;
  }

  document.getElementById('item-detail-icon').textContent=item.icon||cat.icon;
  document.getElementById('item-detail-title').textContent=item.name;

  // Badges — dark pill style matching city/cat hero badges
  const badges=[];
  if(item.price)badges.push({text:'💰 '+item.price,gold:true});
  if(item.rating)badges.push({text:'⭐ '+item.rating,gold:false});
  const city=cities.find(c=>c.id===item.cityId);
  const country=city?countries.find(c=>c.id===city.countryId):null;
  if(city)badges.push({text:(city.icon||'🏙')+' '+city.name,gold:false});
  if(country)badges.push({text:country.flag+' '+country.name,gold:false});
  document.getElementById('item-detail-badges').innerHTML=badges.map(b=>
    `<span class="item-detail-badge${b.gold?' gold':''}">${b.text}</span>`).join('');
  // Desc + tags
  document.getElementById('id-desc').textContent=item.desc||'';
  document.getElementById('id-tags').innerHTML=(item.tags||'').split(',').filter(Boolean)
    .map(t=>`<span class="city-block-tag">${t.trim()}</span>`).join('');
  // Info grid
  const infoCells=[];
  if(item.price)infoCells.push({label:'Price',val:item.price});
  if(item.rating)infoCells.push({label:'Rating',val:item.rating});
  if(item.address)infoCells.push({label:'Address',val:item.address});
  if(item.openingHours)infoCells.push({label:'Hours',val:item.openingHours});
  if(item.phone)infoCells.push({label:'Phone',val:item.phone});
  const infoBlock=document.getElementById('id-info-block');
  if(infoCells.length){
    infoBlock.style.display='block';
    document.getElementById('id-info-grid').innerHTML=infoCells.map(c=>
      `<div class="item-detail-info-cell"><div class="item-detail-info-cell-label">${c.label}</div><div class="item-detail-info-cell-val">${c.val}</div></div>`).join('');
  } else { infoBlock.style.display='none'; }
  // Long desc
  const ldBlock=document.getElementById('id-longdesc-block');
  if(item.longDesc){ldBlock.style.display='block';document.getElementById('id-longdesc').textContent=item.longDesc;}
  else ldBlock.style.display='none';
  // CTA bar (website + directions)
  const ctaBar=document.getElementById('id-cta-bar');
  const ctaBlock=document.getElementById('id-cta-block');
  const ctas=[];
  const mapsQuery=item.mapCoords||item.address||item.name;
  if(item.website)ctas.push(`<a class="item-detail-cta" href="${item.website}" target="_blank" rel="noopener">🌐 Visit Website</a>`);
  if(mapsQuery)ctas.push(`<a class="item-detail-cta outline" href="${getGoogleMapsSearchUrl(mapsQuery)}" target="_blank" rel="noopener">📍 View on Google Maps</a>`);
  if(mapsQuery)ctas.push(`<a class="item-detail-cta outline" href="${getGoogleMapsDirectionsUrl(mapsQuery)}" target="_blank" rel="noopener">🧭 Get Directions</a>`);
  if(item.phone)ctas.push(`<a class="item-detail-cta outline" href="tel:${item.phone}">📞 Call</a>`);
  if(ctas.length){ctaBlock.style.display='block';ctaBar.innerHTML=ctas.join('');}
  else ctaBlock.style.display='none';
  // Gallery
  const galleryBlock=document.getElementById('id-gallery-block');
  const galleryImgs=(item.gallery||'').split(',').map(s=>s.trim()).filter(Boolean);
  if(galleryImgs.length){
    galleryBlock.style.display='block';
    document.getElementById('id-gallery').innerHTML=galleryImgs.map(url=>
      `<div class="item-detail-gallery-img" style="background-image:url('${url}')"></div>`).join('');
  } else galleryBlock.style.display='none';
  // Location actions — open Google Maps directly instead of embedding a paid map
  const mapBlock=document.getElementById('id-map-block');
  const mapActions=document.getElementById('id-map-actions');
  if(item.mapCoords||item.address||item.name){
    const q=item.mapCoords||item.address||item.name;
    mapBlock.style.display='block';
    mapActions.innerHTML=`
      <a class="item-detail-cta outline" href="${getGoogleMapsSearchUrl(q)}" target="_blank" rel="noopener">📍 Open in Google Maps</a>
      <a class="item-detail-cta outline" href="${getGoogleMapsDirectionsUrl(q)}" target="_blank" rel="noopener">🧭 Start Directions</a>
    `;
  } else {
    mapBlock.style.display='none';
    mapActions.innerHTML='';
  }
  // Special category rendering
  // Events — show date block
  const evtBlock=document.getElementById('id-event-date-block');
  if(evtBlock){
    if(item.category==='events'&&item.openingHours){
      evtBlock.style.display='flex';
      evtBlock.innerHTML=`📅 <span>${item.openingHours}</span>`;
    } else { evtBlock.style.display='none'; }
  }
  // Offers — show discount panel
  const offerBlock=document.getElementById('id-offer-highlight-block');
  if(offerBlock){
    if(item.category==='offers'&&item.price){
      offerBlock.style.display='block';
      offerBlock.innerHTML=`<div class="id-offer-block"><div class="id-offer-headline">${item.price}</div><div class="id-offer-sub">${item.desc||'Special offer — limited time'}</div></div>`;
    } else { offerBlock.style.display='none'; }
  }
  // Destinations — show link list instead of standard desc
  const linksBlock=document.getElementById('id-links-block');
  if(linksBlock){
    if(item.category==='important-links'){
      linksBlock.style.display='block';
      // Parse gallery field as pipe-separated "Label|URL" entries
      const linkEntries=(item.gallery||'').split(',').map(s=>s.trim()).filter(Boolean);
      const mainLink=item.website?[{label:item.name,url:item.website,icon:item.icon||'🔗'}]:[];
      const extraLinks=linkEntries.map(e=>{
        const parts=e.split('|');
        return{label:parts[0]||e,url:parts[1]||e,icon:'🌐'};
      });
      const allLinks=[...mainLink,...extraLinks];
      if(allLinks.length){
        document.getElementById('id-links-list').innerHTML=allLinks.map(l=>
          `<a class="id-link-item" href="${l.url}" target="_blank" rel="noopener">
            <span class="id-link-icon">${l.icon}</span>
            <div class="id-link-body"><div class="id-link-name">${l.label}</div><div class="id-link-url">${l.url}</div></div>
            <span class="id-link-arrow">→</span>
          </a>`).join('');
      }
    } else { linksBlock.style.display='none'; }
  }
  // Reviews
  _currentItemId=item.id;
  _reviewStars=0;
  renderReviews(item);
  // Show page
  hideHomeSections();
  document.getElementById('country-page').style.display='none';
  document.getElementById('city-cats').style.display='none';
  document.getElementById('cat-listing').style.display='none';
  document.getElementById('item-detail').style.display='block';
  const tipsElItem=document.getElementById('tips');if(tipsElItem)tipsElItem.style.display='none';
  safeScrollTop();
}

// ── Reviews system ────────────────────────────────────────────────────────────
let _currentItemId=null, _reviewStars=0;

function setReviewStar(n){
  _reviewStars=n;
  document.querySelectorAll('.star-picker-btn').forEach((btn,i)=>{
    btn.classList.toggle('active', i<n);
  });
}

function renderReviews(item){
  const reviews=(item.reviews||[]);
  // Rating summary
  const sumEl=document.getElementById('id-rating-summary');
  if(reviews.length){
    const avg=reviews.reduce((s,r)=>s+r.stars,0)/reviews.length;
    const rounded=Math.round(avg*10)/10;
    const counts=[5,4,3,2,1].map(s=>({s,c:reviews.filter(r=>r.stars===s).length}));
    const fullStars=Math.floor(avg);
    const halfStar=avg-fullStars>=0.5;
    const starsHtml=Array.from({length:5},(_,i)=>{
      const filled=i<fullStars?'var(--gold)':i===fullStars&&halfStar?'var(--gold)':'rgba(245,240,232,.2)';
      return`<span class="id-rating-star-big" style="color:${filled}">★</span>`;
    }).join('');
    const barsHtml=counts.map(({s,c})=>`
      <div class="id-rating-bar-row">
        <span class="id-rating-bar-label">${s}★</span>
        <div class="id-rating-bar-track"><div class="id-rating-bar-fill" style="width:${reviews.length?Math.round(c/reviews.length*100):0}%"></div></div>
        <span style="font-size:.72rem;color:rgba(245,240,232,.45);width:20px">${c}</span>
      </div>`).join('');
    sumEl.style.display='flex';
    sumEl.innerHTML=`
      <div>
        <div class="id-rating-big">${rounded}</div>
        <div class="id-rating-stars-row">${starsHtml}</div>
        <div class="id-rating-count">${reviews.length} review${reviews.length!==1?'s':''}</div>
      </div>
      <div class="id-rating-bars">${barsHtml}</div>`;
  } else {
    sumEl.style.display='none';
  }
  // Review cards
  const listEl=document.getElementById('id-reviews-list');
  if(reviews.length){
    listEl.innerHTML=[...reviews].reverse().map(r=>{
      const stars=Array.from({length:5},(_,i)=>`<span class="id-review-star" style="color:${i<r.stars?'var(--gold)':'rgba(13,13,13,.15)'}">★</span>`).join('');
      return`<div class="id-review-card">
        <div class="id-review-header">
          <div>
            <div class="id-review-author">${r.author||'Anonymous'}</div>
            <div class="id-review-date">${r.date||''}</div>
          </div>
          <div class="id-review-stars">${stars}</div>
        </div>
        <div class="id-review-body">${r.text||''}</div>
      </div>`;
    }).join('');
  } else {
    listEl.innerHTML='<p style="font-size:.88rem;color:rgba(13,13,13,.4);padding:8px 0">No reviews yet. Be the first!</p>';
  }
  // Reset star picker
  setReviewStar(0);
  const nameEl=document.getElementById('id-review-name');
  const textEl=document.getElementById('id-review-text');
  if(nameEl)nameEl.value='';
  if(textEl)textEl.value='';
}

function submitReview(){
  if(!_currentItemId){return;}
  const name=document.getElementById('id-review-name').value.trim()||'Anonymous';
  const text=document.getElementById('id-review-text').value.trim();
  if(!_reviewStars){alert('Please select a star rating.');return;}
  if(!text){alert('Please write a review.');return;}
  const idx=(cityItems||[]).findIndex(x=>x.id===_currentItemId);
  if(idx<0)return;
  if(!cityItems[idx].reviews)cityItems[idx].reviews=[];
  cityItems[idx].reviews.push({
    author:name,
    stars:_reviewStars,
    text:text,
    date:new Date().toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'}),
    ts:Date.now()
  });
  saveAll();
  renderReviews(cityItems[idx]);
  showToast('Review posted ✓');
}
function showCountry(){
  hideHomeSections();
  document.getElementById('city-cats').style.display='none';
  document.getElementById('cat-listing').style.display='none';
  document.getElementById('item-detail').style.display='none';
  const tipsEl=document.getElementById('tips');if(tipsEl)tipsEl.style.display='none';
  document.getElementById('country-page').style.display='block';
  safeScrollTop();
}
function _homeSectionIds(){
  return ['hero','countries','main-footer','tips','featured-cities-section','featured-restaurants-section','featured-attractions-section','featured-offers-section'];
}
function showHome(){
  _homeSectionIds().forEach(id=>{
    const el=document.getElementById(id);
    if(el) el.style.display='';
  });
  ['country-page','city-cats','cat-listing','item-detail','admin-page','login-page','profile-page','signup-page'].forEach(id=>{
    const el=document.getElementById(id);
    if(el) el.style.display='none';
  });
  const footer=document.getElementById('main-footer')||document.querySelector('footer');
  if(footer) footer.style.display='';
  currentCountryId=null;
  currentCityId=null;
  currentCatKey=null;
  safeScrollTop();
}
function extractVideoId(v){
  if(!v)return'';
  const m=v.match(/(?:youtu\.be\/|v=|embed\/)([A-Za-z0-9_-]{11})/);
  return m?m[1]:v.length===11?v:'';
}

