window.addEventListener('scroll',()=>{
  const nav=document.getElementById('main-nav');
  if(nav) nav.classList.toggle('scrolled',window.scrollY>60);
});

// ===================== LOGIN =====================
function openLogin(){document.getElementById('login-modal').classList.add('show')}
function closeLogin(){document.getElementById('login-modal').classList.remove('show')}
function doLogin(){
  const e=document.getElementById('login-email').value.trim().toLowerCase();
  const p=document.getElementById('login-pass').value;
  const result=prototypeAuthenticate(e,p);
  if(result && result.user && result.user.role==='superadmin'){
    loggedIn=true;
    prototypeSetCurrentUser(result.user);
    closeLogin();
    openAdmin();
    document.getElementById('login-error').style.display='none';
    updateFloatingAccountButton();
  }else{
    document.getElementById('login-error').textContent='Invalid superadmin email or password. Please try again.';
    document.getElementById('login-error').style.display='block';
  }
}
document.getElementById('login-pass').addEventListener('keydown',e=>{if(e.key==='Enter')doLogin()});



// ===================== ADMIN CORE =====================

function openAdmin(){
  if(!loggedIn){openLogin();return}
  _homeSectionIds().concat(['country-page','city-cats','cat-listing','item-detail']).forEach(id=>{
    const el=document.getElementById(id); if(el) el.style.display='none';
  });
  const admin=document.getElementById('admin-page');
  if(admin) admin.style.display='block';
  window.scrollTo({top:0});
  apInitAll();
}
function closeAdmin(){
  const admin=document.getElementById('admin-page');
  if(admin) admin.style.display='none';
  _homeSectionIds().forEach(id=>{const el=document.getElementById(id); if(el) el.style.display='';});
  currentCountryId=null;currentCityId=null;currentCatKey=null;
  window.scrollTo({top:0,behavior:'smooth'});
}
function doLogout(){loggedIn=false;closeAdmin();showToast('Signed out');}

function apTab(id,btn){
  document.querySelectorAll('.ap-tab-pane').forEach(p=>p.classList.remove('active'));
  document.querySelectorAll('.ap-nav-tab').forEach(t=>t.classList.remove('active'));
  const pane=document.getElementById(id);
  if(pane)pane.classList.add('active');
  if(btn)btn.classList.add('active');
}

function apInitAll(){
  apPopulateSelects();
  renderApCountries();
  renderApCities();
  renderApCountryPages();
  renderApCityPages();
  renderApCityItems();
  renderApReviews();
  renderApTips();
  renderApAds();
  loadSettingsForm();
  loadPaletteForm();
  aiPopulateSelectors();
  if(typeof renderAnalytics==='function') renderAnalytics();
  if(typeof renderExportStats==='function') renderExportStats();
}

function apPopulateSelects(){
  // Country filters for cities
  const countryOpts='<option value="">All Countries</option>'+countries.map(c=>`<option value="${c.id}">${c.flag} ${c.name}</option>`).join('');
  const cityFilters=['ap-city-country-filter','ap-citypage-country-filter'];
  cityFilters.forEach(id=>{const el=document.getElementById(id);if(el)el.innerHTML=countryOpts;});
  // City filter for items
  const cityOpts='<option value="">All Cities</option>'+cities.map(c=>{
    const country=countries.find(x=>x.id===c.countryId);
    return`<option value="${c.id}">${c.icon||'🏙'} ${c.name}${country?' ('+country.name+')':''}`;
  }).join('');
  ['ap-ci-city-filter','ap-rev-city-filter'].forEach(id=>{
    const el=document.getElementById(id);if(el)el.innerHTML=cityOpts;
  });
}

// ===================== FEATURED CAROUSELS ADMIN =====================

const FEATURED_CAROUSEL_DEFS = [
  {key:'cities',    label:'🏙 Featured Cities',       desc:'Cities carousel — top of homepage',  type:'city'},
  {key:'restaurants',label:'🍽 Featured Restaurants', desc:'Restaurants carousel',               type:'item'},
  {key:'attractions',label:'🏛 Featured Attractions', desc:'Attractions carousel',               type:'item'},
  {key:'offers',    label:'🏷️ Featured Offers',        desc:'Offers carousel',                    type:'item'},
];

function loadFeaturedSettings(){
  return JSON.parse(localStorage.getItem('ab_featured')||'{}');
}
function saveFeaturedSettings(data){
  localStorage.setItem('ab_featured',JSON.stringify(data));
}

function renderApFeatured(){
  const container=document.getElementById('ap-featured-panels');
  if(!container)return;
  const feat=loadFeaturedSettings();
  container.innerHTML=FEATURED_CAROUSEL_DEFS.map(def=>{
    const pinned=feat[def.key]||[];
    const items=def.type==='city'
      ?cities.map(c=>({id:c.id,label:`${c.icon||'🏙'} ${c.name}`,sub:c.countryId?((countries.find(x=>x.id===c.countryId)||{}).name||''):''}))
      :(cityItems||[]).filter(i=>i.category===def.key).map(i=>({id:i.id,label:`${i.icon||'📌'} ${i.name}`,sub:(cities.find(c=>c.id===i.cityId)||{}).name||''}));
    const pinnedSet=new Set(pinned);
    const checkedHtml=pinned.map((id,idx)=>{
      const it=items.find(x=>x.id===id);
      if(!it)return'';
      return`<div style="display:flex;align-items:center;gap:8px;padding:7px 10px;background:var(--cream);border-radius:8px;margin-bottom:5px;font-size:.82rem">
        <span style="color:var(--gold);font-weight:700;min-width:18px">${idx+1}</span>
        <span style="flex:1">${it.label}</span>
        <span style="font-size:.72rem;color:rgba(13,13,13,.4)">${it.sub}</span>
        <button onclick="featuredMoveUp('${def.key}','${id}')" style="border:none;background:none;cursor:pointer;padding:0 3px;font-size:.9rem" title="Move up">↑</button>
        <button onclick="featuredMoveDown('${def.key}','${id}')" style="border:none;background:none;cursor:pointer;padding:0 3px;font-size:.9rem" title="Move down">↓</button>
        <button onclick="featuredRemove('${def.key}','${id}')" style="border:none;background:#ffe5e5;color:#c0392b;cursor:pointer;padding:2px 7px;border-radius:5px;font-size:.72rem">✕</button>
      </div>`;
    }).join('');
    const availableHtml=items.filter(x=>!pinnedSet.has(x.id)).map(it=>
      `<option value="${it.id}">${it.label}${it.sub?' — '+it.sub:''}</option>`
    ).join('');
    return`<div style="background:var(--card-bg);border:1px solid var(--border);border-radius:var(--radius);padding:20px">
      <div style="font-family:'Playfair Display',serif;font-size:1rem;font-weight:700;margin-bottom:4px">${def.label}</div>
      <div style="font-size:.75rem;color:rgba(13,13,13,.45);margin-bottom:14px">${def.desc} — up to 14 shown</div>
      ${pinned.length?checkedHtml:'<p style="font-size:.8rem;color:rgba(13,13,13,.35);margin-bottom:8px;font-style:italic">All items shown (no pins set)</p>'}
      <div style="display:flex;gap:8px;margin-top:10px">
        <select id="feat-add-${def.key}" style="flex:1;padding:7px 10px;border:1.5px solid var(--border);border-radius:8px;font-size:.8rem;font-family:inherit">
          <option value="">— pin an item —</option>
          ${availableHtml}
        </select>
        <button onclick="featuredAdd('${def.key}')" style="background:var(--gold);color:var(--ink);border:none;padding:7px 14px;border-radius:8px;font-size:.8rem;font-weight:700;cursor:pointer">Add</button>
      </div>
      ${pinned.length?`<button onclick="featuredClear('${def.key}')" style="margin-top:10px;background:#ffe5e5;color:#c0392b;border:none;padding:6px 12px;border-radius:7px;font-size:.75rem;cursor:pointer">Clear all pins</button>`:''}
    </div>`;
  }).join('');
}

function featuredAdd(key){
  const sel=document.getElementById(`feat-add-${key}`);
  if(!sel||!sel.value)return;
  const feat=loadFeaturedSettings();
  if(!feat[key])feat[key]=[];
  if(!feat[key].includes(sel.value))feat[key].push(sel.value);
  saveFeaturedSettings(feat);
  renderFeaturedCarousels();
  showToast('Pinned ✓');
}
function featuredRemove(key,id){
  const feat=loadFeaturedSettings();
  feat[key]=(feat[key]||[]).filter(x=>x!==id);
  saveFeaturedSettings(feat);
  renderFeaturedCarousels();
  showToast('Removed');
}
function featuredMoveUp(key,id){
  const feat=loadFeaturedSettings();
  const arr=feat[key]||[];
  const i=arr.indexOf(id);
  if(i>0){arr.splice(i,1);arr.splice(i-1,0,id);}
  feat[key]=arr;saveFeaturedSettings(feat);renderApFeatured();renderFeaturedCarousels();
}
function featuredMoveDown(key,id){
  const feat=loadFeaturedSettings();
  const arr=feat[key]||[];
  const i=arr.indexOf(id);
  if(i>=0&&i<arr.length-1){arr.splice(i,1);arr.splice(i+1,0,id);}
  feat[key]=arr;saveFeaturedSettings(feat);renderApFeatured();renderFeaturedCarousels();
}
function featuredClear(key){
  if(!confirm('Remove all pins for this carousel? All items will show in default order.'))return;
  const feat=loadFeaturedSettings();
  delete feat[key];
  saveFeaturedSettings(feat);renderApFeatured();renderFeaturedCarousels();showToast('Cleared');
}

// ===================== REVIEWS MODERATION =====================

function renderApReviews(){
  const container=document.getElementById('ap-reviews-list');
  if(!container)return;
  const cityF=document.getElementById('ap-rev-city-filter');
  const starsF=document.getElementById('ap-rev-stars-filter');
  const cityFilter=cityF?cityF.value:'';
  const starsFilter=starsF?parseInt(starsF.value)||0:0;
  const allReviews=[];
  (cityItems||[]).forEach(item=>{
    (item.reviews||[]).forEach((r,rIdx)=>{
      const city=cities.find(c=>c.id===item.cityId);
      if(cityFilter&&item.cityId!==cityFilter)return;
      if(starsFilter&&r.stars!==starsFilter)return;
      allReviews.push({item,itemIdx:(cityItems||[]).indexOf(item),rIdx,r,city});
    });
  });
  if(!allReviews.length){
    container.innerHTML='<div class="ap-empty"><span class="ap-empty-icon">⭐</span>No reviews found.</div>';
    return;
  }
  // Sort newest first
  allReviews.sort((a,b)=>(b.r.ts||0)-(a.r.ts||0));
  container.innerHTML=allReviews.map(({item,itemIdx,rIdx,r,city})=>{
    const stars='⭐'.repeat(r.stars||0);
    const date=r.ts?new Date(r.ts).toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'}):'';
    return`<div style="background:var(--card-bg);border:1px solid var(--border);border-radius:12px;padding:16px 20px;display:flex;gap:14px;align-items:flex-start">
      <div style="flex:1;min-width:0">
        <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-bottom:6px">
          <span style="font-size:.85rem;font-weight:700;color:var(--ink)">${item.icon||'📌'} ${item.name}</span>
          <span style="font-size:.72rem;color:rgba(13,13,13,.4)">${city?city.icon+' '+city.name:''}</span>
          <span style="font-size:.9rem">${stars}</span>
          <span style="font-size:.72rem;color:rgba(13,13,13,.4)">${date}</span>
        </div>
        <div style="font-size:.82rem;font-weight:700;color:var(--ink);margin-bottom:3px">${r.author||'Anonymous'}</div>
        <p style="font-size:.85rem;color:rgba(13,13,13,.65);line-height:1.6;margin:0">${r.text||''}</p>
      </div>
      <button onclick="deleteReview(${itemIdx},${rIdx})" style="background:#ffe5e5;color:#c0392b;border:none;padding:6px 12px;border-radius:8px;font-size:.75rem;font-weight:700;cursor:pointer;white-space:nowrap;flex-shrink:0">Delete</button>
    </div>`;
  }).join('');
}

function deleteReview(itemIdx,rIdx){
  if(!confirm('Delete this review?'))return;
  if(cityItems[itemIdx]&&cityItems[itemIdx].reviews){
    cityItems[itemIdx].reviews.splice(rIdx,1);
    saveAll();
    renderApReviews();
    showToast('Review deleted');
  }
}

// ===================== SLIDE-IN FORM =====================

let _apFormSave=null;
function openApForm(heading, bodyHtml, onSave, onDelete){
  document.getElementById('ap-form-heading').textContent=heading;
  document.getElementById('ap-form-body').innerHTML=bodyHtml;
  const actions=document.getElementById('ap-form-actions');
  actions.innerHTML='';
  const saveBtn=document.createElement('button');
  saveBtn.className='admin-btn admin-btn-primary';
  saveBtn.style.flex='1';
  saveBtn.textContent='Save';
  saveBtn.onclick=function(e){
    // Ripple effect
    const ripple=document.createElement('span');
    ripple.className='btn-ripple';
    const rect=saveBtn.getBoundingClientRect();
    const size=Math.max(rect.width,rect.height)*1.2;
    ripple.style.cssText=`width:${size}px;height:${size}px;left:${e.clientX-rect.left-size/2}px;top:${e.clientY-rect.top-size/2}px`;
    saveBtn.appendChild(ripple);
    setTimeout(()=>ripple.remove(),600);
    // Brief visual lock
    saveBtn.textContent='Saving…';
    saveBtn.disabled=true;
    setTimeout(()=>{
      saveBtn.textContent='Save';
      saveBtn.disabled=false;
    },900);
    onSave();
  };
  actions.appendChild(saveBtn);
  const cancelBtn=document.createElement('button');
  cancelBtn.className='admin-btn';
  cancelBtn.style.cssText='background:var(--cream);color:var(--ink);width:auto;padding:11px 20px';
  cancelBtn.textContent='Cancel';
  cancelBtn.onclick=closeApForm;
  actions.appendChild(cancelBtn);
  if(onDelete){
    const delBtn=document.createElement('button');
    delBtn.className='admin-btn admin-btn-danger';
    delBtn.style.cssText='width:auto;padding:11px 14px';
    delBtn.textContent='Delete';
    delBtn.onclick=onDelete;
    actions.appendChild(delBtn);
  }
  document.getElementById('ap-form-overlay').classList.add('open');
}
function closeApForm(){
  document.getElementById('ap-form-overlay').classList.remove('open');
}
function apFormOverlayClick(e){
  if(e.target===document.getElementById('ap-form-overlay'))closeApForm();
}

// Image field helpers (inside form panel)
function apImgField(uploadId, urlId, previewId, removeId, hint){
  return`<div class="form-group">
    <label>Upload Image File</label>
    <input type="file" id="${uploadId}" accept="image/*" onchange="apPreviewImg('${uploadId}','${previewId}','${removeId}','${urlId}')">
    <small class="form-hint">${hint}</small>
    <div class="ap-cloudinary-row">
      <button type="button" class="ap-cloudinary-btn" onclick="apConfigureCloudinary()">Configure Cloudinary</button>
      <button type="button" class="ap-cloudinary-btn" onclick="apShowCloudinaryConfig()">View Config</button>
    </div>
    <div id="${uploadId}-status" class="ap-upload-status info"></div>
    <div id="${previewId}" class="img-preview-box" style="display:none"></div>
  </div>
  <div class="form-group">
    <label>Or Cloudinary / Image URL</label>
    <input type="text" id="${urlId}" placeholder="https://..." oninput="apSyncUrl('${urlId}','${previewId}','${removeId}')">
  </div>
  <button type="button" class="ap-img-remove-btn" id="${removeId}" onclick="apRemoveImg('${uploadId}','${urlId}','${previewId}','${removeId}')" style="display:none">✕ Remove Image</button>`;
}

function apGetCloudinaryConfig(){
  try{
    return JSON.parse(localStorage.getItem('ab_cloudinary')||'null')||null;
  }catch(e){ return null; }
}
function apSetCloudinaryConfig(cfg){
  localStorage.setItem('ab_cloudinary', JSON.stringify(cfg||{}));
}
function apConfigureCloudinary(){
  const current = apGetCloudinaryConfig() || {};
  const cloudName = prompt('Enter Cloudinary cloud name', current.cloudName || '');
  if(cloudName === null) return;
  const uploadPreset = prompt('Enter Cloudinary unsigned upload preset', current.uploadPreset || '');
  if(uploadPreset === null) return;
  const folder = prompt('Optional: default folder name', current.folder || 'abledinos');
  if(folder === null) return;
  apSetCloudinaryConfig({cloudName: cloudName.trim(), uploadPreset: uploadPreset.trim(), folder: folder.trim()});
  alert('Cloudinary configuration saved.');
}
function apShowCloudinaryConfig(){
  const cfg = apGetCloudinaryConfig();
  if(!cfg || !cfg.cloudName || !cfg.uploadPreset){
    alert('Cloudinary is not configured yet.');
    return;
  }
  alert('Cloud name: ' + cfg.cloudName + '\nUpload preset: ' + cfg.uploadPreset + '\nFolder: ' + (cfg.folder || '(none)'));
}
function apSetUploadStatus(inputId, type, msg){
  const box = document.getElementById(inputId + '-status');
  if(!box) return;
  box.className = 'ap-upload-status show ' + (type || 'info');
  box.textContent = msg || '';
}
async function apUploadToCloudinary(file){
  const cfg = apGetCloudinaryConfig();
  if(!cfg || !cfg.cloudName || !cfg.uploadPreset){
    throw new Error('Cloudinary is not configured. Click "Configure Cloudinary" first.');
  }
  const endpoint = `https://api.cloudinary.com/v1_1/${cfg.cloudName}/image/upload`;
  const form = new FormData();
  form.append('file', file);
  form.append('upload_preset', cfg.uploadPreset);
  if(cfg.folder) form.append('folder', cfg.folder);

  const res = await fetch(endpoint, { method:'POST', body: form });
  const data = await res.json();
  if(!res.ok || !data.secure_url){
    throw new Error((data && data.error && data.error.message) || 'Cloudinary upload failed.');
  }
  return data.secure_url;
}
async function apPreviewImg(uploadId, previewId, removeId, urlId){
  const input=document.getElementById(uploadId);
  const preview=document.getElementById(previewId);
  const urlInput=document.getElementById(urlId);
  if(input&&input.files&&input.files[0]){
    try{
      apSetUploadStatus(uploadId, 'info', 'Uploading image to Cloudinary...');
      const uploadedUrl = await apUploadToCloudinary(input.files[0]);
      preview.style.backgroundImage = `url('${uploadedUrl}')`;
      preview.style.display = 'block';
      delete preview._b64;
      delete preview._removed;
      preview._url = uploadedUrl;
      if(urlInput) urlInput.value = uploadedUrl;
      const rb=document.getElementById(removeId); if(rb) rb.style.display='';
      apSetUploadStatus(uploadId, 'ok', 'Upload complete. Cloudinary URL saved.');
      showToast('Image uploaded ✓');
    }catch(err){
      console.error(err);
      apSetUploadStatus(uploadId, 'err', err.message || 'Upload failed.');
      alert(err.message || 'Cloudinary upload failed.');
      input.value = '';
    }
  }
}
function apSyncUrl(urlId, previewId, removeId){
  const val=document.getElementById(urlId).value.trim();
  const preview=document.getElementById(previewId);
  if(val){
    preview.style.backgroundImage=`url('${val}')`;
    preview.style.display='block';
    delete preview._b64;
    delete preview._removed;
    preview._url = val;
    const rb=document.getElementById(removeId);if(rb)rb.style.display='';
  }else{
    preview.style.display='none';
    preview.style.backgroundImage='';
    delete preview._b64;
    delete preview._url;
    const rb=document.getElementById(removeId);if(rb)rb.style.display='none';
  }
}
function apRemoveImg(uploadId, urlId, previewId, removeId){
  document.getElementById(uploadId).value='';
  document.getElementById(urlId).value='';
  const p=document.getElementById(previewId);
  p.style.display='none';
  p.style.backgroundImage='';
  delete p._b64;
  delete p._url;
  p._removed=true;
  const rb=document.getElementById(removeId);if(rb)rb.style.display='none';
  const status=document.getElementById(uploadId+'-status');
  if(status){
    status.className='ap-upload-status info';
    status.style.display='none';
    status.textContent='';
  }
}
function apGetImg(previewId){
  const p=document.getElementById(previewId);
  if(!p) return '';
  if(p._removed) return '__removed__';
  return p._url || p._b64 || '';
}
function apResolveImg(previewId, fallback){
  const v=apGetImg(previewId);
  if(v==='__removed__') return '';
  return v || fallback || '';
}
function apSetImg(img, uploadId, urlId, previewId, removeId){
  const preview=document.getElementById(previewId);
  const rb=document.getElementById(removeId);
  const urlEl=document.getElementById(urlId);
  if(img){
    if(preview){preview.style.backgroundImage=`url('${img}')`;preview.style.display='block';preview._b64=img;}
    if(urlEl&&img.startsWith('http'))urlEl.value=img;
    if(rb)rb.style.display='';
  } else {
    if(preview){preview.style.display='none';preview._b64=null;}
    if(rb)rb.style.display='none';
    if(urlEl)urlEl.value='';
  }
  if(uploadId){const u=document.getElementById(uploadId);if(u)u.value='';}
}

// ===================== COUNTRIES =====================

function renderApCountries(){
  const grid=document.getElementById('ap-countries-grid');
  if(!grid)return;
  if(!countries.length){grid.innerHTML='<div class="ap-empty"><span class="ap-empty-icon">🗺</span>No countries yet. Add one!</div>';return;}
  grid.innerHTML=countries.map(c=>{
    const img=c.heroImage||'';
    const imgStyle=img?`background-image:url('${img}');background-color:#ddd`:`background:linear-gradient(135deg,${c.gradient||'#2d5f8a,#c9a84c'})`;
    return`<div class="ap-card">
      ${c.featured=='1'?'<div class="ap-card-badge">✦ Featured</div>':''}
      <div class="ap-card-img" style="${imgStyle}">
        ${!img?`<span style="position:relative;z-index:2;font-size:5rem;display:block;text-align:center;filter:drop-shadow(0 4px 12px rgba(13,13,13,.35))">${c.flag}</span>`:''}
        <div class="ap-card-img-overlay"></div>
      </div>
      <div class="ap-card-body">
        <div class="ap-card-title">${c.flag} ${c.name}</div>
        <div class="ap-card-meta">${c.season||''} · ${c.currency||''} · ${c.lang||''}</div>
        <div class="ap-card-actions">
          <button class="ap-card-edit" onclick="openCountryForm('${c.id}')">Edit Tile</button>
          <button class="ap-card-del" onclick="deleteCountry('${c.id}')">Del</button>
        </div>
      </div>
    </div>`;
  }).join('');
}

function openCountryForm(id){
  const c=id?countries.find(x=>x.id===id):null;
  const body=`
    <div class="form-row">
      <div class="form-group"><label>Country Name</label><input type="text" id="cf-name" placeholder="e.g. France" value="${c?c.name:''}"></div>
      <div class="form-group"><label>Flag Emoji</label><input type="text" id="cf-flag" placeholder="🇫🇷" value="${c?c.flag:''}"></div>
    </div>
    <div class="form-group"><label>Short Description</label><textarea id="cf-desc" placeholder="Describe this country...">${c?c.desc:''}</textarea></div>
    <div class="form-row">
      <div class="form-group"><label>Best Season</label><input type="text" id="cf-season" placeholder="Apr – Oct" value="${c?c.season:''}"></div>
      <div class="form-group"><label>Currency</label><input type="text" id="cf-currency" placeholder="EUR €" value="${c?c.currency:''}"></div>
    </div>
    <div class="form-row">
      <div class="form-group"><label>Language</label><input type="text" id="cf-lang" placeholder="French" value="${c?c.lang:''}"></div>
      <div class="form-group"><label>Fallback Gradient</label><input type="text" id="cf-gradient" placeholder="#2d5f8a,#c9a84c" value="${c?c.gradient||'':''}"></div>
    </div>
    <div class="form-group"><label>Featured?</label><select id="cf-featured"><option value="0"${!c||c.featured!='1'?' selected':''}>No</option><option value="1"${c&&c.featured=='1'?' selected':''}>Yes — show badge</option></select></div>
    <hr class="admin-divider">
    <p class="ap-section-label">🖼 Shared Square Image — 1200 × 1200 px recommended</p>
    ${apImgField('cf-img','cf-img-url','cf-img-preview','cf-img-remove','Cloudinary URL or direct image URL. Use one square image for the hero inset, tiles and carousels. Keep the subject centered.')}
  `;
  openApForm(c?`Edit: ${c.flag} ${c.name}`:'New Country', body,
    ()=>saveCountryForm(id),
    id?()=>{ if(confirm('Delete this country and all its cities?')){deleteCountry(id);closeApForm();} }:null
  );
  if(c)apSetImg(c.heroImage||'','cf-img','cf-img-url','cf-img-preview','cf-img-remove');
}

function saveCountryForm(id){
  const name=document.getElementById('cf-name').value.trim();
  if(!name){alert('Country name required');return;}
  const img=apResolveImg('cf-img-preview', id?countries.find(x=>x.id===id)?.heroImage||'':'');
  const obj={
    id:id||uid(), name,
    flag:document.getElementById('cf-flag').value.trim(),
    desc:document.getElementById('cf-desc').value.trim(),
    season:document.getElementById('cf-season').value.trim(),
    currency:document.getElementById('cf-currency').value.trim(),
    lang:document.getElementById('cf-lang').value.trim(),
    gradient:document.getElementById('cf-gradient').value.trim()||'#2d5f8a,#c9a84c',
    featured:document.getElementById('cf-featured').value,
    heroImage:img,
    pageTagline:id?countries.find(x=>x.id===id)?.pageTagline||'':'',
    pageHeroImage:id?countries.find(x=>x.id===id)?.pageHeroImage||'':'',
  };
  if(id){const i=countries.findIndex(x=>x.id===id);if(i>=0)countries[i]=obj;else countries.push(obj);}
  else countries.push(obj);
  saveAll();renderApCountries();renderCountries();apPopulateSelects();
  renderApCountryPages();closeApForm();showToast('Country saved ✓');
}

function deleteCountry(id){
  if(!confirm('Delete this country and all its cities?'))return;
  // Collect city IDs belonging to this country and their item IDs for featured cleanup
  const cityIds=cities.filter(x=>x.countryId===id).map(x=>x.id);
  const itemIds=(cityItems||[]).filter(x=>cityIds.includes(x.cityId)).map(x=>x.id);
  countries=countries.filter(x=>x.id!==id);
  cities=cities.filter(x=>x.countryId!==id);
  cityItems=(cityItems||[]).filter(x=>!cityIds.includes(x.cityId));
  // Purge from featured
  const feat=loadFeaturedSettings();let dirty=false;
  cityIds.concat(itemIds).forEach(rid=>{
    Object.keys(feat).forEach(k=>{
      if(feat[k]&&feat[k].includes(rid)){feat[k]=feat[k].filter(x=>x!==rid);dirty=true;}
    });
  });
  if(dirty)saveFeaturedSettings(feat);
  saveAll();renderApCountries();renderApCities();renderApCityPages();
  renderApCountryPages();renderApCityItems();renderApFeatured();renderFeaturedCarousels();renderCountries();apPopulateSelects();showToast('Country deleted');
}

// ===================== CITIES =====================

function renderApCities(){
  const grid=document.getElementById('ap-cities-grid');
  if(!grid)return;
  const filter=document.getElementById('ap-city-country-filter');
  const fv=filter?filter.value:'';
  const list=fv?cities.filter(c=>c.countryId===fv):cities;
  if(!list.length){grid.innerHTML='<div class="ap-empty"><span class="ap-empty-icon">🏙</span>No cities yet. Add one!</div>';return;}
  grid.innerHTML=list.map(c=>{
    const country=countries.find(x=>x.id===c.countryId);
    const img=c.heroImage||'';
    const imgStyle=img?`background-image:url('${img}');background-color:#ddd`:`background:linear-gradient(135deg,${c.gradient||'#c85a3c,#c9a84c'})`;
    return`<div class="ap-card">
      <div class="ap-card-img" style="${imgStyle}">
        ${!img?`<span style="position:relative;z-index:2;font-size:5rem;display:block;text-align:center;filter:drop-shadow(0 4px 12px rgba(13,13,13,.35))">${c.icon||'🏙'}</span>`:''}
        <div class="ap-card-img-overlay"></div>
      </div>
      <div class="ap-card-body">
        <div class="ap-card-title">${c.icon||'🏙'} ${c.name}</div>
        <div class="ap-card-meta">${country?country.flag+' '+country.name:''} · ${c.bestFor||''}</div>
        <div class="ap-card-actions">
          <button class="ap-card-edit" onclick="openCityForm('${c.id}')">Edit Tile</button>
          <button class="ap-card-del" onclick="deleteCity('${c.id}')">Del</button>
        </div>
      </div>
    </div>`;
  }).join('');
}

function openCityForm(id){
  const c=id?cities.find(x=>x.id===id):null;
  const countryOpts=countries.map(x=>`<option value="${x.id}"${c&&c.countryId===x.id?' selected':''}>${x.flag} ${x.name}</option>`).join('');
  const body=`
    <div class="form-group"><label>Country</label><select id="cityf-country">${countryOpts}</select></div>
    <div class="form-row">
      <div class="form-group"><label>City Name</label><input type="text" id="cityf-name" placeholder="e.g. Paris" value="${c?c.name:''}"></div>
      <div class="form-group"><label>Icon Emoji</label><input type="text" id="cityf-icon" placeholder="🗼" value="${c?c.icon||'':''}"></div>
    </div>
    <div class="form-group"><label>Description</label><textarea id="cityf-desc" placeholder="Short description...">${c?c.desc:''}</textarea></div>
    <div class="form-group"><label>Highlights <span class="form-hint-inline">(comma-separated)</span></label><input type="text" id="cityf-highlights" placeholder="Eiffel Tower, Louvre..." value="${c?c.highlights||'':''}"></div>
    <div class="form-group"><label>Best For</label><input type="text" id="cityf-bestfor" placeholder="Romance, Art, Food" value="${c?c.bestFor||'':''}"></div>
    <div class="form-group"><label>Fallback Gradient</label><input type="text" id="cityf-gradient" placeholder="#c85a3c,#c9a84c" value="${c?c.gradient||'':''}"></div>
    <div class="form-group"><label>Homepage Featured Cities Order <span class="form-hint-inline">(1, 2, 3... leave blank to remove from homepage carousel)</span></label><input type="number" min="1" step="1" id="cityf-featured-order" placeholder="e.g. 1" value="${c&&c.featuredOrder?c.featuredOrder:''}"></div>
    <hr class="admin-divider">
    <p class="ap-section-label">🖼 Shared Square Image — 1200 × 1200 px recommended</p>
    ${apImgField('cityf-img','cityf-img-url','cityf-img-preview','cityf-img-remove','Cloudinary URL or direct image URL. Use one square image for the hero inset, tiles and carousels. Keep the subject centered.')}
  `;
  openApForm(c?`Edit: ${c.icon||'🏙'} ${c.name}`:'New City', body,
    ()=>saveCityForm(id),
    id?()=>{ if(confirm('Delete this city?')){deleteCity(id);closeApForm();} }:null
  );
  if(c)apSetImg(c.heroImage||'','cityf-img','cityf-img-url','cityf-img-preview','cityf-img-remove');
}

function saveCityForm(id){
  const name=document.getElementById('cityf-name').value.trim();
  if(!name){alert('City name required');return;}
  const img=apResolveImg('cityf-img-preview', id?cities.find(x=>x.id===id)?.heroImage||'':'');
  const existing=id?cities.find(x=>x.id===id):null;
  const obj={
    id:id||uid(),
    countryId:document.getElementById('cityf-country').value,
    name,
    icon:document.getElementById('cityf-icon').value.trim(),
    desc:document.getElementById('cityf-desc').value.trim(),
    highlights:document.getElementById('cityf-highlights').value.trim(),
    bestFor:document.getElementById('cityf-bestfor').value.trim(),
    gradient:document.getElementById('cityf-gradient').value.trim()||'#c85a3c,#c9a84c',
    featuredOrder:(()=>{const v=document.getElementById('cityf-featured-order').value.trim(); return v?Math.max(1,parseInt(v,10)||1):'';})(),
    heroImage:img,
    // Preserve page fields
    pageHeroImage:existing?.pageHeroImage||'',
    video:existing?.video||'',
    latLng:existing?.latLng||'',
    attractions:existing?.attractions||'',
    restaurants:existing?.restaurants||'',
    gettingAround:existing?.gettingAround||'',
    culture:existing?.culture||'',
    catImages:existing?.catImages||{},
  };
  if(id){const i=cities.findIndex(x=>x.id===id);if(i>=0)cities[i]=obj;else cities.push(obj);}
  else cities.push(obj);
  saveAll();renderApCities();renderApCityPages();renderFeaturedCarousels();apPopulateSelects();closeApForm();showToast('City saved ✓');
}

function deleteCity(id){
  if(!confirm('Delete this city?'))return;
  // Collect item IDs belonging to this city for featured cleanup
  const itemIds=(cityItems||[]).filter(x=>x.cityId===id).map(x=>x.id);
  cities=cities.filter(x=>x.id!==id);
  cityItems=(cityItems||[]).filter(x=>x.cityId!==id);
  // Purge city and its items from featured
  const feat=loadFeaturedSettings();let dirty=false;
  [id].concat(itemIds).forEach(rid=>{
    Object.keys(feat).forEach(k=>{
      if(feat[k]&&feat[k].includes(rid)){feat[k]=feat[k].filter(x=>x!==rid);dirty=true;}
    });
  });
  if(dirty)saveFeaturedSettings(feat);
  saveAll();renderApCities();renderApCityPages();renderApCityItems();renderApFeatured();renderFeaturedCarousels();apPopulateSelects();showToast('City deleted');
}

// ===================== COUNTRY PAGES =====================

function renderApCountryPages(){
  const grid=document.getElementById('ap-countrypages-grid');
  if(!grid)return;
  if(!countries.length){grid.innerHTML='<div class="ap-empty"><span class="ap-empty-icon">📄</span>No countries yet.</div>';return;}
  grid.innerHTML=countries.map(c=>{
    const img=c.pageHeroImage||c.heroImage||'';
    const imgStyle=img?`background-image:url('${img}')`:
      `background:linear-gradient(135deg,${c.gradient||'#2d5f8a,#c9a84c'})`;
    return`<div class="ap-card">
      <div class="ap-card-img" style="${imgStyle}">
        <span style="position:relative;z-index:2;font-size:2.5rem">${c.flag}</span>
        <div class="ap-card-img-overlay"></div>
      </div>
      <div class="ap-card-body">
        <div class="ap-card-title">${c.name}</div>
        <div class="ap-card-meta">${c.pageTagline?'"'+c.pageTagline.slice(0,50)+(c.pageTagline.length>50?'…':'')+'"':'No tagline set'}</div>
        <div class="ap-card-actions">
          <button class="ap-card-edit" onclick="openCountryPageForm('${c.id}')">Edit Page</button>
        </div>
      </div>
    </div>`;
  }).join('');
}

function openCountryPageForm(id){
  const c=countries.find(x=>x.id===id);
  if(!c)return;
  const body=`
    <div class="form-group"><label>Page Tagline / Subtitle</label><textarea id="cpf-tagline" placeholder="A short evocative line...">${c.pageTagline||c.desc||''}</textarea></div>
    <div class="form-group"><label>About This Country <span class="form-hint-inline">longer description shown on country page</span></label><textarea id="cpf-about" placeholder="Tell visitors what makes this country special..." style="min-height:100px">${c.pageAbout||''}</textarea></div>
    <div class="form-row">
      <div class="form-group"><label>Currency</label><input type="text" id="cpf-currency" placeholder="e.g. EUR (€)" value="${c.currency||''}"></div>
      <div class="form-group"><label>Language(s)</label><input type="text" id="cpf-language" placeholder="e.g. French" value="${c.language||''}"></div>
    </div>
    <hr class="admin-divider">
    <p class="ap-section-label">🖼 Image</p>
    <small class="form-hint" style="display:block">This page uses the same shared square image as the country tile, carousel, and hero inset. Edit it from <strong>Countries → Edit Tile</strong>.</small>
  `;
  openApForm(`Page: ${c.flag} ${c.name}`, body, ()=>saveCountryPageForm(id));
}

function saveCountryPageForm(id){
  const i=countries.findIndex(x=>x.id===id);if(i<0)return;
  countries[i].pageTagline=document.getElementById('cpf-tagline').value.trim();
  countries[i].pageAbout=document.getElementById('cpf-about').value.trim();
  countries[i].currency=document.getElementById('cpf-currency').value.trim();
  countries[i].language=document.getElementById('cpf-language').value.trim();
  // Image is managed from the main country editor so each country has a single source of truth.
  countries[i].pageHeroImage=countries[i].heroImage||countries[i].pageHeroImage||'';
  saveAll();renderApCountryPages();renderCountries();renderFeaturedCarousels();closeApForm();showToast('Country page saved ✓');
}

// ===================== CITY PAGES =====================

function renderApCityPages(){
  const grid=document.getElementById('ap-citypages-grid');
  if(!grid)return;
  const filter=document.getElementById('ap-citypage-country-filter');
  const fv=filter?filter.value:'';
  const list=fv?cities.filter(c=>c.countryId===fv):cities;
  if(!list.length){grid.innerHTML='<div class="ap-empty"><span class="ap-empty-icon">📋</span>No cities yet.</div>';return;}
  const CAT_ICONS={restaurants:'🍽',attractions:'🏛',activities:'🎯','getting-around':'🚇',shopping:'🛍',hotels:'🏨','local-cuisine':'🥘','important-links':'📍',events:'🎉',offers:'🏷️'};
  grid.innerHTML=list.map(c=>{
    const country=countries.find(x=>x.id===c.countryId);
    const img=c.pageHeroImage||c.heroImage||'';
    const imgStyle=img?`background-image:url('${img}')`:
      `background:linear-gradient(135deg,${c.gradient||'#c85a3c,#c9a84c'})`;
    const hasDots=[c.pageHeroImage||c.heroImage,c.latLng,c.video,c.attractions,c.restaurants,c.gettingAround,c.culture];
    const dots=hasDots.map((v,i)=>`<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${v?'var(--sage)':'var(--border)'};margin-right:3px" title="${['Photo','Map','Video','Attractions','Food','Transport','Culture'][i]}"></span>`).join('');
    return`<div class="ap-card">
      <div class="ap-card-img" style="${imgStyle}">
        <span style="position:relative;z-index:2;font-size:2rem">${c.icon||'🏙'}</span>
        <div class="ap-card-img-overlay"></div>
      </div>
      <div class="ap-card-body">
        <div class="ap-card-title">${c.name}</div>
        <div class="ap-card-meta">${country?country.flag+' '+country.name:''}</div>
        <div style="margin-bottom:10px">${dots}</div>
        <div class="ap-card-actions">
          <button class="ap-card-edit" onclick="openCityPageForm('${c.id}')">Edit Page</button>
        </div>
      </div>
    </div>`;
  }).join('');
}

function openCityPageForm(id){
  const c=cities.find(x=>x.id===id);
  if(!c)return;
  const catImgs=c.catImages||{};
  const catImageFields=Object.entries(CAT_META).map(([key,cat])=>`
    <div class="form-group">
      <label>${cat.icon} ${cat.label} Image <span class="form-hint-inline">700 × 420 px — replaces sample</span></label>
      <input type="text" id="cpgf-cat-${key}" placeholder="https://... or leave blank to use sample" value="${catImgs[key]||''}">
    </div>`).join('');
  const body=`
    <p class="ap-section-label">🖼 Image</p>
    <small class="form-hint" style="display:block;margin-bottom:14px">This page uses the same shared square image as the city tile, carousel, and hero inset. Edit it from <strong>Cities → Edit Tile</strong>.</small>
    <hr class="admin-divider">
    <div class="form-group"><label>About This City <span class="form-hint-inline">shown in the City Guide panel below the category grid</span></label>
      <textarea id="cpgf-about" placeholder="Describe the city's character, highlights and tips for visitors..." style="min-height:110px">${c.pageAbout||''}</textarea>
    </div>
    <hr class="admin-divider">
    <div class="form-group"><label>Map Coordinates <span class="form-hint-inline">(lat,lng)</span></label><input type="text" id="cpgf-latlng" placeholder="48.8566,2.3522" value="${c.latLng||''}"></div>
    <div class="form-group"><label>YouTube Video ID or URL</label><input type="text" id="cpgf-video" placeholder="e.g. dQw4w9WgXcQ" value="${c.video||''}"></div>
    <hr class="admin-divider">
    <p class="ap-section-label">📂 Category Tile Images</p>
    <small class="form-hint" style="display:block;margin-bottom:14px">These images appear on the city's category hub cards. Leave blank to use the built-in sample images.</small>
    ${catImageFields}
  `;
  openApForm(`Page: ${c.icon||'🏙'} ${c.name}`, body, ()=>saveCityPageForm(id));
}

function saveCityPageForm(id){
  const i=cities.findIndex(x=>x.id===id);if(i<0)return;
  // Image is managed from the main city editor so each city has a single source of truth.
  cities[i].pageHeroImage=cities[i].heroImage||cities[i].pageHeroImage||'';
  cities[i].pageAbout=document.getElementById('cpgf-about').value.trim();
  cities[i].latLng=document.getElementById('cpgf-latlng').value.trim();
  cities[i].video=document.getElementById('cpgf-video').value.trim();
  // Save per-category images
  const catImgs={};
  Object.keys(CAT_META).forEach(key=>{
    const el=document.getElementById(`cpgf-cat-${key}`);
    if(el&&el.value.trim())catImgs[key]=el.value.trim();
  });
  cities[i].catImages=catImgs;
  saveAll();
  renderApCityPages();   // refresh City Pages admin tab
  renderApCities();      // refresh Cities admin tab tile immediately
  renderFeaturedCarousels(); // refresh homepage carousels immediately
  closeApForm();showToast('City page saved ✓');
}

// ===================== CITY ITEMS =====================


function renderApCityItems(){
  const grid=document.getElementById('ap-cityitems-grid');
  if(!grid)return;
  const cityF=document.getElementById('ap-ci-city-filter');
  const catF=document.getElementById('ap-ci-cat-filter');
  let list=cityItems||[];
  if(cityF&&cityF.value)list=list.filter(i=>i.cityId===cityF.value);
  if(catF&&catF.value)list=list.filter(i=>i.category===catF.value);
  if(!list.length){grid.innerHTML='<div class="ap-empty"><span class="ap-empty-icon">📦</span>No items yet. Add some!</div>';return;}
  grid.innerHTML=list.map(item=>{
    const cat=CAT_META[item.category]||{icon:'📌',label:item.category,bg:'linear-gradient(135deg,#888,#aaa)'};
    const city=cities.find(c=>c.id===item.cityId);
    const img=item.image||'';
    const imgStyle=img?`background-image:url('${img}')`:cat.bg;
    const hasDots=[item.pageHeroImage,item.longDesc,item.openingHours,item.website,item.phone,item.mapCoords,item.gallery];
    const dotLabels=['📷 Hero','📄 About','🕐 Hours','🌐 Site','📞 Phone','📍 Map','🖼 Gallery'];
    const dots=hasDots.map((v,i)=>
      `<span style="font-size:.68rem;background:${v?'var(--sage)':'var(--border)'};color:${v?'#fff':'rgba(13,13,13,.4)'};padding:2px 7px;border-radius:50px;margin-right:2px">${dotLabels[i]}</span>`
    ).join('');
    return`<div class="ap-card">
      <div class="ap-card-img" style="${imgStyle}">
        ${!img?`<span style="position:relative;z-index:2;font-size:5rem;display:block;text-align:center;filter:drop-shadow(0 4px 12px rgba(13,13,13,.35))">${item.icon||cat.icon}</span>`:''}
        <div class="ap-card-img-overlay"></div>
        <div class="ap-card-badge">${cat.icon} ${cat.label}</div>
      </div>
      <div class="ap-card-body">
        <div class="ap-card-title">${item.name}</div>
        <div class="ap-card-meta">${city?city.icon+' '+city.name:''}${item.price?' · '+item.price:''}${item.rating?' · '+item.rating:''}</div>
        <div style="margin:6px 0 12px;display:flex;flex-wrap:wrap;gap:3px">${dots}</div>
        <div class="ap-card-actions">
          <button class="ap-card-edit" onclick="openCityItemForm('${item.id}')">Edit</button>
          <button class="ap-card-del" onclick="deleteCityItemById('${item.id}')">Del</button>
        </div>
      </div>
    </div>`;
  }).join('');
}

function openCityItemForm(id){
  const item=id?(cityItems||[]).find(x=>x.id===id):null;
  const cityOpts=cities.map(c=>{
    const country=countries.find(x=>x.id===c.countryId);
    return`<option value="${c.id}"${item&&item.cityId===c.id?' selected':''}>${c.icon||'🏙'} ${c.name}${country?' ('+country.name+')':''}`;
  }).join('');
  const catOpts=Object.entries(CAT_META).map(([k,v])=>`<option value="${k}"${item&&item.category===k?' selected':''}>${v.icon} ${v.label}</option>`).join('');
  const body=`
    <p class="ap-section-label" style="margin-bottom:8px">📋 Basic Info</p>
    <div class="form-row">
      <div class="form-group"><label>City</label><select id="cif-city">${cityOpts}</select></div>
      <div class="form-group"><label>Category</label><select id="cif-cat">${catOpts}</select></div>
    </div>
    <div class="form-row">
      <div class="form-group"><label>Name</label><input type="text" id="cif-name" placeholder="e.g. Le Jules Verne" value="${item?item.name:''}"></div>
      <div class="form-group"><label>Icon Emoji</label><input type="text" id="cif-icon" placeholder="🍽" value="${item?item.icon||'':''}"></div>
    </div>
    <div class="form-group"><label>Short Description</label><textarea id="cif-desc" placeholder="Short description shown on the tile...">${item?item.desc||'':''}</textarea></div>
    <div class="form-group"><label>Tags <span class="form-hint-inline">(comma-separated)</span></label><input type="text" id="cif-tags" placeholder="Fine Dining, French, Views" value="${item?item.tags||'':''}"></div>
    <div class="form-row">
      <div class="form-group"><label>Price</label><input type="text" id="cif-price" placeholder="€€€ or Free" value="${item?item.price||'':''}"></div>
      <div class="form-group"><label>Rating</label><input type="text" id="cif-rating" placeholder="4.8 ★" value="${item?item.rating||'':''}"></div>
    </div>
    <div class="form-group"><label>Address</label><input type="text" id="cif-address" placeholder="Champ de Mars, Paris" value="${item?item.address||'':''}"></div>
    <div class="form-group"><label>Homepage Featured Order <span class="form-hint-inline">(1, 2, 3... leave blank to remove from this category carousel)</span></label><input type="number" min="1" step="1" id="cif-featured-order" placeholder="e.g. 1" value="${item&&item.featuredOrder?item.featuredOrder:''}"></div>
    <small class="form-hint" style="display:block;margin:-4px 0 10px">This controls the order inside the homepage ${item?(CAT_META[item.category]?.label||item.category):'category'} carousel.</small>
    <hr class="admin-divider">
    <p class="ap-section-label">🖼 Shared Square Image — 1200 × 1200 px recommended</p>
    ${apImgField('cif-img','cif-img-url','cif-img-preview','cif-img-remove','Cloudinary URL or direct image URL. Use one square image for the hero inset, tiles and carousels. Keep the subject centered.')}
    <hr class="admin-divider">
    <p class="ap-section-label">📝 Detail Page</p>
    <small class="form-hint" style="display:block;margin-bottom:12px">This detail page uses the same shared square image as the item tile and carousels.</small>
    <div class="form-group"><label>Long Description / About</label>
      <textarea id="cif-longdesc" placeholder="Full description shown on the detail page — history, what makes it special, tips for visitors..." style="min-height:120px">${item?item.longDesc||'':''}</textarea>
    </div>
    <hr class="admin-divider">
    <p class="ap-section-label">📋 Practical Info</p>
    <div class="form-row">
      <div class="form-group"><label>Opening Hours</label><input type="text" id="cif-hours" placeholder="Mon–Fri 9am–10pm" value="${item?item.openingHours||'':''}"></div>
      <div class="form-group"><label>Phone</label><input type="text" id="cif-phone" placeholder="+33 1 23 45 67 89" value="${item?item.phone||'':''}"></div>
    </div>
    <div class="form-group"><label>Website URL</label><input type="url" id="cif-website" placeholder="https://..." value="${item?item.website||'':''}"></div>
    <div class="form-group"><label>Map Coordinates <span class="form-hint-inline">(lat,lng)</span></label><input type="text" id="cif-coords" placeholder="48.8566,2.3522" value="${item?item.mapCoords||'':''}"></div>
    <hr class="admin-divider">
    <div class="form-group"><label>Gallery Image URLs <span class="form-hint-inline">(comma-separated, 700×420px each)</span></label>
      <textarea id="cif-gallery" placeholder="https://img1.jpg, https://img2.jpg, ...">${item?item.gallery||'':''}</textarea>
    </div>
  `;
  openApForm(item?`Edit: ${item.name}`:'New City Item', body,
    ()=>saveCityItemForm(id),
    id?()=>{ if(confirm('Delete this item?')){deleteCityItemById(id);closeApForm();} }:null
  );
  if(item){
    apSetImg(item.image||'','cif-img','cif-img-url','cif-img-preview','cif-img-remove');
  }
}

function saveCityItemForm(id){
  const name=document.getElementById('cif-name').value.trim();
  if(!name){alert('Name required');return;}
  if(!cityItems)cityItems=[];
  const img=apResolveImg('cif-img-preview', id?(cityItems.find(x=>x.id===id)?.image||''):'');
  const obj={
    id:id||uid(),
    cityId:document.getElementById('cif-city').value,
    category:document.getElementById('cif-cat').value,
    name,
    icon:document.getElementById('cif-icon').value.trim(),
    desc:document.getElementById('cif-desc').value.trim(),
    tags:document.getElementById('cif-tags').value.trim(),
    price:document.getElementById('cif-price').value.trim(),
    rating:document.getElementById('cif-rating').value.trim(),
    address:document.getElementById('cif-address').value.trim(),
    image:img,
    pageHeroImage:img,
    featuredOrder:(()=>{const v=document.getElementById('cif-featured-order').value.trim(); return v?Math.max(1,parseInt(v,10)||1):'';})(),
    longDesc:document.getElementById('cif-longdesc').value.trim(),
    openingHours:document.getElementById('cif-hours').value.trim(),
    phone:document.getElementById('cif-phone').value.trim(),
    website:document.getElementById('cif-website').value.trim(),
    mapCoords:document.getElementById('cif-coords').value.trim(),
    gallery:document.getElementById('cif-gallery').value.trim(),
    reviews:id?(cityItems.find(x=>x.id===id)?.reviews||[]):[],
  };
  if(id){const i=cityItems.findIndex(x=>x.id===id);if(i>=0)cityItems[i]=obj;else cityItems.push(obj);}
  else cityItems.push(obj);
  saveAll();renderApCityItems();renderFeaturedCarousels();closeApForm();showToast('Item saved ✓');
}

function deleteCityItemById(id){
  if(!confirm('Delete this item?'))return;
  cityItems=(cityItems||[]).filter(x=>x.id!==id);
  // Purge from featured
  const feat=loadFeaturedSettings();let dirty=false;
  Object.keys(feat).forEach(k=>{
    if(feat[k]&&feat[k].includes(id)){feat[k]=feat[k].filter(x=>x!==id);dirty=true;}
  });
  if(dirty)saveFeaturedSettings(feat);
  saveAll();renderApCityItems();renderApFeatured();renderFeaturedCarousels();showToast('Item deleted');
}

