// ===================== ADS =====================

function normalizeAd(ad){
  if(!ad)return ad;
  return {
    ...ad,
    body: ad.body||'',
    order: Number.isFinite(Number(ad.order))?Number(ad.order):999,
    enabled: ad.enabled!==false
  };
}

function sortAdsForDisplay(list){
  return (list||[])
    .map(normalizeAd)
    .sort((a,b)=>{
      const ao=Number.isFinite(Number(a.order))?Number(a.order):999;
      const bo=Number.isFinite(Number(b.order))?Number(b.order):999;
      if(ao!==bo)return ao-bo;
      return String(a.title||'').localeCompare(String(b.title||''));
    });
}

function renderApAds(){
  const grid=document.getElementById('ap-ads-grid');
  if(!grid)return;
  const loaded=sortAdsForDisplay(ads||[]);
  if(!loaded.length){grid.innerHTML='<div class="ap-empty"><span class="ap-empty-icon">📢</span>No ads yet.</div>';return;}
  const LOC_LABELS={'tips-after-2':'Tips (after 2nd)','tips-after-4':'Tips (after 4th)','countries-after-3':'Countries (after 3rd)','cities-after-2':'Cities (after 2nd)','hero-bottom':'Hero Bottom'};
  grid.innerHTML=loaded.map(a=>{
    const imgStyle=a.image?`background-image:url('${a.image}')`:(`background:${a.bg||'#c9a84c'}`);
    return`<div class="ap-card">
      <div class="ap-card-img" style="${imgStyle}">
        <div class="ap-card-img-overlay"></div>
      </div>
      <div class="ap-card-body">
        <div class="ap-card-title">${a.title||'Untitled'}</div>
        <div class="ap-card-meta">📍 ${LOC_LABELS[a.location]||a.location} · Order: ${a.order??999} · ${a.enabled===false?'Disabled':'Active'} · CTA: ${a.cta||'—'}</div>
        ${a.body?`<div class="ap-card-sub" style="font-size:.9rem;color:#6b7280;margin-top:6px">${a.body}</div>`:''}
        <div class="ap-card-actions">
          <button class="ap-card-edit" onclick="openAdForm('${a.id}')">Edit</button>
          <button class="ap-card-del" onclick="deleteAdById('${a.id}')">Del</button>
        </div>
      </div>
    </div>`;
  }).join('');
}

function openAdForm(id){
  const a=normalizeAd(id?(ads||[]).find(x=>x.id===id):null);
  const locOpts=['tips-after-2','tips-after-4','countries-after-3','cities-after-2','hero-bottom']
    .map(v=>`<option value="${v}"${a&&a.location===v?' selected':''}>${AD_LOCATION_LABELS[v]||v}</option>`).join('');
  const body=`
    <div class="form-group"><label>Ad Title</label><input type="text" id="adf-title" placeholder="e.g. Hotels 30% Off" value="${a?a.title:''}"></div>
    <div class="form-group"><label>Ad Copy</label><textarea id="adf-body" rows="3" placeholder="Short supporting text for the ad card">${a?a.body||'':''}</textarea></div>
    <div class="form-row">
      <div class="form-group"><label>Location</label><select id="adf-location">${locOpts}</select></div>
      <div class="form-group"><label>Background Color</label><input type="color" id="adf-bg" value="${a?a.bg||'#c9a84c':'#c9a84c'}"></div>
    </div>
    <div class="form-row">
      <div class="form-group"><label>Display Order</label><input type="number" id="adf-order" min="1" step="1" placeholder="1" value="${a&&Number.isFinite(Number(a.order))&&Number(a.order)!==999?a.order:''}"></div>
      <div class="form-group"><label>Status</label><label style="display:flex;align-items:center;gap:8px;margin-top:12px"><input type="checkbox" id="adf-enabled" ${!a||a.enabled!==false?'checked':''}> Show this ad</label></div>
    </div>
    <div class="form-group"><label>Image URL <span class="form-hint-inline">Cloudinary or direct image URL</span></label><input type="url" id="adf-img-url" placeholder="https://..." value="${a?a.image||'':''}"></div>
    <div class="form-group"><label>Upload Image <span class="form-hint-inline">optional — square or landscape works best</span></label>
      <input type="file" id="adf-img" accept="image/*" onchange="apPreviewImg('adf-img','adf-preview','adf-remove')">
      <div id="adf-preview" class="img-preview-box" style="display:none"></div>
      <button class="ap-img-remove-btn" id="adf-remove" onclick="apRemoveImg('adf-img','adf-img-url','adf-preview','adf-remove')" style="display:none">✕ Remove</button>
    </div>
    <div class="form-group"><label>CTA Button Text</label><input type="text" id="adf-cta" placeholder="Book Now" value="${a?a.cta||'':''}"></div>
    <div class="form-group"><label>External Link</label><input type="url" id="adf-link" placeholder="https://..." value="${a?a.link||'':''}"></div>
  `;
  openApForm(a?`Edit: ${a.title}`:'New Ad', body,
    ()=>saveAdForm(id),
    id?()=>{ if(confirm('Delete?')){deleteAdById(id);closeApForm();} }:null
  );
  if(a&&a.image)apSetImg(a.image,'adf-img','adf-img-url','adf-preview','adf-remove');
}

function saveAdForm(id){
  const title=document.getElementById('adf-title').value.trim();
  const body=document.getElementById('adf-body').value.trim();
  const cta=document.getElementById('adf-cta').value.trim();
  const link=document.getElementById('adf-link').value.trim();
  if(!title||!cta||!link){alert('Title, CTA and Link required');return;}
  const fileInput=document.getElementById('adf-img');
  const file=fileInput&&fileInput.files&&fileInput.files[0];
  const imageUrl=(document.getElementById('adf-img-url')?.value||'').trim();
  const orderRaw=(document.getElementById('adf-order')?.value||'').trim();
  const order=orderRaw?Number(orderRaw):999;
  function persist(imgData){
    if(!ads)ads=[];
    const obj=normalizeAd({id:id||uid(),title,body,location:document.getElementById('adf-location').value,
      bg:document.getElementById('adf-bg').value,cta,link,image:imgData,order,
      enabled:!!document.getElementById('adf-enabled')?.checked});
    if(id){const i=ads.findIndex(x=>x.id===id);if(i>=0)ads[i]=obj;else ads.push(obj);}
    else ads.push(obj);
    saveAds();renderApAds();renderHome();closeApForm();showToast('Ad saved ✓');
  }
  if(file){const r=new FileReader();r.onload=e=>persist(e.target.result);r.readAsDataURL(file);}
  else {
    const preview=document.getElementById('adf-preview');
    if(preview&&preview._removed) persist('');
    else if(imageUrl) persist(imageUrl);
    else persist(id?(ads||[]).find(x=>x.id===id)?.image||'':'');
  }
}

function deleteAdById(id){
  if(!confirm('Delete this ad?'))return;
  ads=(ads||[]).filter(x=>x.id!==id);
  saveAds();renderApAds();renderHome();showToast('Ad deleted');
}

// ===================== ADS DATA & ADMIN =====================
const DEFAULT_ADS = [
  {id:'ad1',title:'Hotels 30% Off',body:'Special rates for quick city breaks and weekend escapes.',location:'tips-after-2',bg:'#ff6b6b',image:'',cta:'Book Now',link:'https://booking.com',order:1,enabled:true},
  {id:'ad2',title:'Flights from $29',body:'Compare fares and lock in limited-time flight deals.',location:'countries-after-3',bg:'#4ecdc4',image:'',cta:'Find Deals',link:'https://kayak.com',order:1,enabled:true}
];
const AD_LOCATION_LABELS = {
  'tips-after-2':'Tips (after 2nd)','tips-after-4':'Tips (after 4th)',
  'countries-after-3':'Countries (after 3rd)','cities-after-2':'Cities (after 2nd)','hero-bottom':'Hero Bottom'
};
function loadAds(){
  ads=sortAdsForDisplay(JSON.parse(localStorage.getItem('ab_ads')||JSON.stringify(DEFAULT_ADS)));
}
function saveAds(){
  ads=sortAdsForDisplay(ads||[]);
  localStorage.setItem('ab_ads',JSON.stringify(ads));
  if(typeof abQueueRemoteStateSave==='function'){
    try{ abQueueRemoteStateSave(); }catch(_e){}
  }
}
// ===================== ADS RENDERING =====================
function isDarkColor(hex){
  const n=parseInt((hex||'#000').replace('#',''),16);
  const r=(n>>16)&255,g=(n>>8)&255,b=n&255;
  return(0.299*r+0.587*g+0.114*b)<140;
}
function buildAdTileHTML(a){
  a=normalizeAd(a);
  const bg=a.bg||'#c9a84c';
  const dark=isDarkColor(bg);
  const tc=dark?'#fff':'#0d0d0d';
  const imgHtml=a.image?`<div style="width:100%;height:140px;background:url('${a.image}') center/cover no-repeat;border-radius:10px 10px 0 0"></div>`:'';
  const copyHtml=a.body?`<p style="font-size:.92rem;line-height:1.5;opacity:.88;margin:0 0 14px">${a.body}</p>`:'';
  const ctaHtml=(a.cta&&a.link)?`<a href="${a.link}" target="_blank" rel="noopener" style="display:inline-block;background:${dark?'rgba(255,255,255,.18)':'rgba(0,0,0,.12)'};color:${tc};padding:8px 20px;border-radius:50px;font-size:.8rem;font-weight:700;text-decoration:none">${a.cta} →</a>`:'';
  return`<div style="background:${bg};border-radius:var(--radius);padding:${a.image?'0':'28px'} 0 0;overflow:hidden;box-shadow:var(--shadow)">
    ${imgHtml}
    <div style="padding:${a.image?'18px':'0'} 24px 24px;color:${tc}">
      <p style="font-size:.63rem;letter-spacing:.25em;text-transform:uppercase;opacity:.6;margin-bottom:6px;font-family:'Space Mono',monospace">Sponsored</p>
      <h3 style="font-family:'Playfair Display',serif;font-size:1.1rem;font-weight:700;margin-bottom:${a.body?'10px':'12px'};line-height:1.25">${a.title}</h3>
      ${copyHtml}
      ${ctaHtml}
    </div>
  </div>`;
}
function injectAds(){
  document.querySelectorAll('.ad-tile-wrapper').forEach(el=>el.remove());
  if(!ads||!ads.length)return;
  const byLoc={};
  sortAdsForDisplay((ads||[]).filter(a=>normalizeAd(a).enabled!==false)).forEach(a=>{(byLoc[a.location]=byLoc[a.location]||[]).push(normalizeAd(a))});
  ['tips-after-2','tips-after-4'].forEach(loc=>{
    if(!byLoc[loc])return;
    const grid=document.getElementById('tips-grid');if(!grid)return;
    const idx=loc==='tips-after-2'?2:4;
    const cards=[...grid.children];
    const w=document.createElement('div');w.className='ad-tile-wrapper';
    w.innerHTML=byLoc[loc].map(buildAdTileHTML).join('');
    if(cards[idx])grid.insertBefore(w,cards[idx]);else grid.appendChild(w);
  });
  if(byLoc['countries-after-3']){
    const grid=document.getElementById('countries-grid');if(grid){
      const cards=[...grid.children];
      const w=document.createElement('div');w.className='ad-tile-wrapper';
      w.innerHTML=byLoc['countries-after-3'].map(buildAdTileHTML).join('');
      if(cards[3])grid.insertBefore(w,cards[3]);else grid.appendChild(w);
    }
  }
  if(byLoc['cities-after-2']){
    const grid=document.getElementById('cities-grid');if(grid){
      const cards=[...grid.children];
      const w=document.createElement('div');w.className='ad-tile-wrapper';
      w.innerHTML=byLoc['cities-after-2'].map(buildAdTileHTML).join('');
      if(cards[2])grid.insertBefore(w,cards[2]);else grid.appendChild(w);
    }
  }
  if(byLoc['hero-bottom']){
    const hero=document.getElementById('hero');if(hero){
      let hw=hero.querySelector('.hero-ad-wrapper');
      if(!hw){hw=document.createElement('div');hw.className='hero-ad-wrapper ad-tile-wrapper';hw.style.cssText='position:absolute;bottom:80px;right:40px;width:280px;z-index:3';hero.appendChild(hw);}
      hw.innerHTML=byLoc['hero-bottom'].map(buildAdTileHTML).join('');
    }
  }
}

// ===================== SETTINGS =====================
function loadSettingsForm(){
  ['s-hero1','s-hero2','s-herosub','s-stat1n','s-stat1l','s-stat2n','s-stat2l','s-stat3n','s-stat3l'].forEach(id=>{
    const key=id.replace('s-','').replace(/-/g,'');
    const map={'hero1':'hero1','hero2':'hero2','herosub':'herosub','stat1n':'stat1n','stat1l':'stat1l',
      'stat2n':'stat2n','stat2l':'stat2l','stat3n':'stat3n','stat3l':'stat3l'};
    const el=document.getElementById(id);
    if(el)el.value=settings[id.slice(2)]||'';
  });
  // direct mapping
  const s=settings||{};
  const set=(id,val)=>{const e=document.getElementById(id);if(e)e.value=val||'';};
  set('s-hero1',s.hero1);set('s-hero2',s.hero2);set('s-herosub',s.herosub);
  set('s-stat1n',s.stat1n);set('s-stat1l',s.stat1l);
  set('s-stat2n',s.stat2n);set('s-stat2l',s.stat2l);
  set('s-stat3n',s.stat3n);set('s-stat3l',s.stat3l);
  set('s-cta1label',s.cta1label);set('s-cta1link',s.cta1link);
  set('s-cta2label',s.cta2label);set('s-cta2link',s.cta2link);
}
function saveSettings(){
  const g=(id)=>{const e=document.getElementById(id);return e?e.value:'';};
  settings={
    hero1:g('s-hero1'),hero2:g('s-hero2'),herosub:g('s-herosub'),
    stat1n:g('s-stat1n'),stat1l:g('s-stat1l'),
    stat2n:g('s-stat2n'),stat2l:g('s-stat2l'),
    stat3n:g('s-stat3n'),stat3l:g('s-stat3l'),
    cta1label:g('s-cta1label'),cta1link:g('s-cta1link'),
    cta2label:g('s-cta2label'),cta2link:g('s-cta2link'),
  };
  saveAll();applySettings();showToast('Settings saved ✓');
}
function resetData(){
  if(!confirm('Reset ALL content to defaults?'))return;
  ['ab_countries','ab_cities','ab_tips','ab_citypages','ab_settings','ab_ads','ab_cityitems','ab_cityItems'].forEach(k=>localStorage.removeItem(k));
  loadData();renderHome();apInitAll();showToast('Data reset to defaults ✓');
}

// ===================== PALETTE =====================
const DEFAULT_PALETTE={ink:'#0d0d0d',cream:'#f5f0e8',gold:'#c9a84c',terra:'#c85a3c',sage:'#4a7c6a',sky:'#2d5f8a'};
function lightenHex(hex,amt){
  let n=parseInt(hex.slice(1),16);
  let r=Math.min(255,(n>>16)+amt),g=Math.min(255,((n>>8)&0xff)+amt),b=Math.min(255,(n&0xff)+amt);
  return'#'+[r,g,b].map(x=>x.toString(16).padStart(2,'0')).join('');
}
function applyPalette(p){
  const s=document.documentElement.style;
  s.setProperty('--ink',p.ink);s.setProperty('--cream',p.cream);
  s.setProperty('--gold',p.gold);s.setProperty('--gold-light',lightenHex(p.gold,30));
  s.setProperty('--terra',p.terra);s.setProperty('--sage',p.sage);s.setProperty('--sky',p.sky);
  s.setProperty('--warm-white',lightenHex(p.cream,10));
}
function updatePalettePreview(){
  const ink=document.getElementById('p-ink')?.value||'#0d0d0d';
  const gold=document.getElementById('p-gold')?.value||'#c9a84c';
  const sage=document.getElementById('p-sage')?.value||'#4a7c6a';
  const prev=document.getElementById('palette-preview');
  if(prev)prev.style.background=`linear-gradient(135deg,${ink},${gold},${sage})`;
}
function loadPaletteForm(){
  const p=JSON.parse(localStorage.getItem('ab_palette')||'null')||DEFAULT_PALETTE;
  ['ink','cream','gold','terra','sage','sky'].forEach(k=>{
    const el=document.getElementById('p-'+k);
    if(el){el.value=p[k];el.oninput=updatePalettePreview;}
  });
  updatePalettePreview();
}
function savePalette(){
  const p={};
  ['ink','cream','gold','terra','sage','sky'].forEach(k=>{
    const el=document.getElementById('p-'+k);if(el)p[k]=el.value;
  });
  localStorage.setItem('ab_palette',JSON.stringify(p));
  applyPalette(p);showToast('Palette saved ✓');
}
function loadDefaultPalette(){
  localStorage.removeItem('ab_palette');
  applyPalette(DEFAULT_PALETTE);
  ['ink','cream','gold','terra','sage','sky'].forEach(k=>{
    const el=document.getElementById('p-'+k);if(el)el.value=DEFAULT_PALETTE[k];
  });
  updatePalettePreview();showToast('Palette reset ✓');
}

// ===================== SEARCH =====================

function heroSearchInput(val){
  renderGooglePlacesSuggestions('hero',val);
}

function openSearchWithQuery(query){
  openSearch();
  const input=document.getElementById('search-input');
  if(input){
    input.value=query||'';
    if(query){
      runSearch();
      renderGooglePlacesSuggestions('overlay',query);
    }
  }
  // Clear hero input
  const hi=document.getElementById('hero-search-input');
  if(hi)hi.value='';
  closeGooglePlacesSuggestions('hero');
}

function openSearch(){
  const overlay=document.getElementById('search-overlay');
  overlay.classList.add('open');
  // Populate country dropdown
  const sd=document.getElementById('sd-country');
  sd.innerHTML='<option value="">All Countries</option>'+
    countries.map(c=>`<option value="${c.id}">${c.flag} ${c.name}</option>`).join('');
  document.getElementById('sd-city').innerHTML='<option value="">All Cities</option>';
  document.getElementById('search-input').value='';
  document.getElementById('search-body').innerHTML='<div class="search-empty"><span class="search-empty-icon">🔍</span>Start typing or use the dropdowns to explore</div>';
  closeGooglePlacesSuggestions('overlay');
  setTimeout(()=>document.getElementById('search-input').focus(),80);
}

function closeSearch(){
  document.getElementById('search-overlay').classList.remove('open');
  closeGooglePlacesSuggestions('overlay');
}

// Close on Escape
document.addEventListener('keydown',e=>{
  if(e.key==='Escape')closeSearch();
});

function clearSearch(){
  document.getElementById('search-input').value='';
  document.getElementById('sd-country').value='';
  document.getElementById('sd-city').innerHTML='<option value="">All Cities</option>';
  document.getElementById('sd-city').value='';
  document.getElementById('sd-category').value='';
  document.getElementById('search-body').innerHTML='<div class="search-empty"><span class="search-empty-icon">🔍</span>Start typing or use the dropdowns to explore</div>';
}

function onSdCountry(){
  const countryId=document.getElementById('sd-country').value;
  // Populate city dropdown
  const cityDd=document.getElementById('sd-city');
  if(countryId){
    const citiesForCountry=cities.filter(c=>c.countryId===countryId);
    cityDd.innerHTML='<option value="">All Cities</option>'+
      citiesForCountry.map(c=>`<option value="${c.id}">${c.icon||'🏙'} ${c.name}</option>`).join('');
  } else {
    cityDd.innerHTML='<option value="">All Cities</option>';
  }
  cityDd.value='';
  runSearch();
}

function onSdCity(){
  // When a city is picked, navigate directly and close search
  const cityId=document.getElementById('sd-city').value;
  const catId=document.getElementById('sd-category').value;
  if(cityId&&!catId){
    closeSearch();
    openCity(cityId);
    return;
  }
  if(cityId&&catId){
    closeSearch();
    openCity(cityId);
    setTimeout(()=>openCatListing(cityId,catId),300);
    return;
  }
  runSearch();
}

function onSdCategory(){
  const cityId=document.getElementById('sd-city').value;
  const catId=document.getElementById('sd-category').value;
  if(cityId&&catId){
    closeSearch();
    openCity(cityId);
    setTimeout(()=>openCatListing(cityId,catId),300);
    return;
  }
  runSearch();
}

function runSearch(){
  const query=document.getElementById('search-input').value.trim().toLowerCase();
  const countryFilter=document.getElementById('sd-country').value;
  const cityFilter=document.getElementById('sd-city').value;
  const catFilter=document.getElementById('sd-category').value;
  const body=document.getElementById('search-body');

  // If no query and no filters, show empty state
  if(!query&&!countryFilter&&!cityFilter&&!catFilter){
    body.innerHTML='<div class="search-empty"><span class="search-empty-icon">🔍</span>Start typing or use the dropdowns to explore</div>';
    return;
  }

  const sections=[];

  // ── Countries ──────────────────────────────────────────────────────────────
  if(!cityFilter&&!catFilter){
    let countryResults=countries;
    if(countryFilter)countryResults=countryResults.filter(c=>c.id===countryFilter);
    if(query)countryResults=countryResults.filter(c=>
      c.name.toLowerCase().includes(query)||
      (c.desc||'').toLowerCase().includes(query)||
      (c.lang||'').toLowerCase().includes(query)
    );
    if(countryResults.length){
      const cards=countryResults.map(c=>{
        const img=c.heroImage||'';
        const thumbStyle=img?`background-image:url('${img}');background-color:#ddd`:`background:linear-gradient(135deg,${c.gradient||'#2d5f8a,#c9a84c'})`;
        return`<div class="search-result-card" onclick="closeSearch();openCountry('${c.id}')">
          <div class="search-result-thumb" style="${thumbStyle}">${!img?c.flag:''}</div>
          <div class="search-result-body">
            <div class="search-result-name">${c.flag} ${c.name}</div>
            <div class="search-result-meta">${c.season||''} · ${c.currency||''}</div>
          </div>
          <span class="search-result-type srt-country">Country</span>
        </div>`;
      }).join('');
      sections.push(`<div class="search-section-label">Countries</div><div class="search-results-grid">${cards}</div>`);
    }
  }

  // ── Cities ─────────────────────────────────────────────────────────────────
  if(!catFilter){
    let cityResults=cities;
    if(countryFilter)cityResults=cityResults.filter(c=>c.countryId===countryFilter);
    if(cityFilter)cityResults=cityResults.filter(c=>c.id===cityFilter);
    if(query)cityResults=cityResults.filter(c=>
      c.name.toLowerCase().includes(query)||
      (c.desc||'').toLowerCase().includes(query)||
      (c.bestFor||'').toLowerCase().includes(query)||
      (c.highlights||'').toLowerCase().includes(query)
    );
    if(cityResults.length){
      const cards=cityResults.map(c=>{
        const country=countries.find(x=>x.id===c.countryId);
        const img=c.heroImage||'';
        const thumbStyle=img?`background-image:url('${img}')`:(`background:linear-gradient(135deg,${c.gradient||'#c85a3c,#c9a84c'})`);
        return`<div class="search-result-card" onclick="closeSearch();openCity('${c.id}')">
          <div class="search-result-thumb" style="${thumbStyle}">${!img?c.icon||'🏙':''}</div>
          <div class="search-result-body">
            <div class="search-result-name">${c.icon||'🏙'} ${c.name}</div>
            <div class="search-result-meta">${country?country.flag+' '+country.name:''} · ${c.bestFor||''}</div>
          </div>
          <span class="search-result-type srt-city">City</span>
        </div>`;
      }).join('');
      sections.push(`<div class="search-section-label">Cities</div><div class="search-results-grid">${cards}</div>`);
    }
  }

  // ── Category pages (city + category combos) ────────────────────────────────
  if(catFilter&&!cityFilter){
    let catCityResults=cities;
    if(countryFilter)catCityResults=catCityResults.filter(c=>c.countryId===countryFilter);
    if(query)catCityResults=catCityResults.filter(c=>c.name.toLowerCase().includes(query)||(countries.find(x=>x.id===c.countryId)||{}).name?.toLowerCase().includes(query));
    const cat=CAT_META[catFilter];
    if(cat&&catCityResults.length){
      const cards=catCityResults.map(c=>{
        const country=countries.find(x=>x.id===c.countryId);
        const catImg=(c.catImages&&c.catImages[catFilter])||cat.sampleImage||'';
        const thumbStyle=catImg?`background-image:url('${catImg}')`:cat.bg;
        const count=(cityItems||[]).filter(i=>i.cityId===c.id&&i.category===catFilter).length;
        return`<div class="search-result-card" onclick="closeSearch();openCity('${c.id}');setTimeout(()=>openCatListing('${c.id}','${catFilter}'),300)">
          <div class="search-result-thumb" style="${thumbStyle}"></div>
          <div class="search-result-body">
            <div class="search-result-name">${cat.icon} ${cat.label} in ${c.name}</div>
            <div class="search-result-meta">${country?country.flag+' '+country.name:''} · ${count} item${count!==1?'s':''}</div>
          </div>
          <span class="search-result-type srt-cat">${cat.label}</span>
        </div>`;
      }).join('');
      sections.push(`<div class="search-section-label">${cat.icon} ${cat.label}</div><div class="search-results-grid">${cards}</div>`);
    }
  }

  // ── Items (restaurants, attractions, etc.) ─────────────────────────────────
  if(query||catFilter||cityFilter){
    let itemResults=cityItems||[];
    if(cityFilter)itemResults=itemResults.filter(i=>i.cityId===cityFilter);
    else if(countryFilter){
      const countyCities=cities.filter(c=>c.countryId===countryFilter).map(c=>c.id);
      itemResults=itemResults.filter(i=>countyCities.includes(i.cityId));
    }
    if(catFilter)itemResults=itemResults.filter(i=>i.category===catFilter);
    if(query)itemResults=itemResults.filter(i=>
      i.name.toLowerCase().includes(query)||
      (i.desc||'').toLowerCase().includes(query)||
      (i.tags||'').toLowerCase().includes(query)||
      (i.address||'').toLowerCase().includes(query)
    );
    if(itemResults.length){
      const cards=itemResults.slice(0,24).map(item=>{
        const cat=CAT_META[item.category]||{icon:'📌',label:item.category,bg:'#888'};
        const city=cities.find(c=>c.id===item.cityId);
        const country=city?countries.find(c=>c.id===city.countryId):null;
        const img=item.image||'';
        const thumbStyle=img?`background-image:url('${img}')`:cat.bg;
        return`<div class="search-result-card" onclick="closeSearch();openCity('${item.cityId}');setTimeout(()=>{openCatListing('${item.cityId}','${item.category}');setTimeout(()=>openItemDetail('${item.id}'),300)},300)">
          <div class="search-result-thumb" style="${thumbStyle}">${!img?item.icon||cat.icon:''}</div>
          <div class="search-result-body">
            <div class="search-result-name">${item.icon||cat.icon} ${item.name}</div>
            <div class="search-result-meta">${city?city.name:''}${country?' · '+country.flag+' '+country.name:''}${item.price?' · '+item.price:''}</div>
          </div>
          <span class="search-result-type srt-item">${cat.label}</span>
        </div>`;
      }).join('');
      const total=itemResults.length;
      sections.push(`<div class="search-section-label">Items${total>24?' (showing top 24)':''}</div><div class="search-results-grid">${cards}</div>`);
    }
  }

  if(sections.length){
    body.innerHTML=sections.join('');
  } else {
    body.innerHTML=`<div class="search-empty"><span class="search-empty-icon">😕</span>No results found for "<strong>${query||'your selection'}</strong>"</div>`;
  }
}


function getGoogleMapsSearchUrl(query){
  return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(query||'')}`;
}

function getGoogleMapsDirectionsUrl(destination){
  return `https://www.google.com/maps/dir/?api=1&destination=${encodeURIComponent(destination||'')}`;
}

const GOOGLE_PLACES_STATE={hero:{timer:null,items:[]},overlay:{timer:null,items:[]}};

function getGooglePlacesApiKey(){
  return (window.ABLEDINOS_CONFIG&&window.ABLEDINOS_CONFIG.googlePlacesApiKey||'').trim();
}

function getPlacesSuggestionsContainer(mode){
  return document.getElementById(mode==='hero'?'hero-places-suggestions':'search-places-suggestions');
}

function closeGooglePlacesSuggestions(mode){
  const box=getPlacesSuggestionsContainer(mode);
  if(box){
    box.classList.remove('open');
    box.innerHTML='';
  }
  if(GOOGLE_PLACES_STATE[mode])GOOGLE_PLACES_STATE[mode].items=[];
}

function renderGooglePlacesSuggestions(mode,query){
  const state=GOOGLE_PLACES_STATE[mode];
  if(!state)return;
  clearTimeout(state.timer);
  const trimmed=(query||'').trim();
  if(trimmed.length<3){
    closeGooglePlacesSuggestions(mode);
    return;
  }
  state.timer=setTimeout(()=>fetchGooglePlacesSuggestions(mode,trimmed),220);
}

async function fetchGooglePlacesSuggestions(mode,query){
  const box=getPlacesSuggestionsContainer(mode);
  if(!box)return;
  const apiKey=getGooglePlacesApiKey();
  if(!apiKey){
    renderGooglePlacesSuggestionsBox(mode,query,[],true);
    return;
  }
  try{
    const res=await fetch('https://places.googleapis.com/v1/places:autocomplete',{
      method:'POST',
      headers:{
        'Content-Type':'application/json',
        'X-Goog-Api-Key':apiKey,
        'X-Goog-FieldMask':'suggestions.placePrediction.place,suggestions.placePrediction.placeId,suggestions.placePrediction.text,suggestions.placePrediction.structuredFormat'
      },
      body:JSON.stringify({
        input:query,
        includedPrimaryTypes:['restaurant','tourist_attraction','lodging','museum','cafe','park','shopping_mall','airport','train_station'],
        regionCode:'IN'
      })
    });
    if(!res.ok)throw new Error(`Places request failed: ${res.status}`);
    const data=await res.json();
    const items=(data.suggestions||[]).map(entry=>entry.placePrediction).filter(Boolean).slice(0,5).map(pred=>({
      text:(pred.text&&pred.text.text)||'',
      mainText:(pred.structuredFormat&&pred.structuredFormat.mainText&&pred.structuredFormat.mainText.text)||'',
      secondaryText:(pred.structuredFormat&&pred.structuredFormat.secondaryText&&pred.structuredFormat.secondaryText.text)||'',
      placeId:pred.placeId||'',
      place:pred.place||''
    }));
    renderGooglePlacesSuggestionsBox(mode,query,items,false);
  }catch(err){
    console.warn('Google Places suggestions unavailable',err);
    renderGooglePlacesSuggestionsBox(mode,query,[],true);
  }
}

function renderGooglePlacesSuggestionsBox(mode,query,items,showConfigHint){
  const box=getPlacesSuggestionsContainer(mode);
  if(!box)return;
  GOOGLE_PLACES_STATE[mode].items=items;
  let inner='';
  if(items.length||showConfigHint){
    inner+=`<div class="places-suggestions-head"><div class="places-suggestions-title">Google Maps suggestions</div><div class="places-suggestions-hint">${showConfigHint?'Add your restricted Places key in config.js':'Open selected places directly in Google Maps'}</div></div>`;
  }
  inner+=items.map((item,idx)=>{
    const label=item.mainText||item.text||query;
    const meta=item.secondaryText||'Google Maps place';
    const mapsUrl=getGoogleMapsSearchUrl(item.text||label||query);
    return `<a class="places-suggestion-item" href="${mapsUrl}" target="_blank" rel="noopener" data-mode="${mode}" data-index="${idx}">
      <span class="places-suggestion-icon">📍</span>
      <span class="places-suggestion-body"><span class="places-suggestion-name">${escapeHtml(label)}</span><span class="places-suggestion-meta">${escapeHtml(meta)}</span></span>
      <span class="places-suggestion-badge">Maps</span>
    </a>`;
  }).join('');
  inner+=`<button type="button" class="places-suggestion-footer" onclick="openSearchWithQuery(${JSON.stringify(query)})"><span class="places-suggestion-icon">🔎</span><span class="places-suggestion-body"><span class="places-suggestion-name">Search this site for “${escapeHtml(query)}”</span><span class="places-suggestion-meta">Keep browsing your own curated pages and filters</span></span></button>`;
  box.innerHTML=inner;
  box.classList.add('open');
}

function escapeHtml(str){
  return String(str||'').replace(/[&<>"]/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[ch]));
}
// ===================== RIPPLE HELPER =====================
function apRipple(e){
  const btn=e.currentTarget||e.target;
  if(!btn)return;
  const ripple=document.createElement('span');
  ripple.className='btn-ripple';
  const rect=btn.getBoundingClientRect();
  const size=Math.max(rect.width,rect.height)*1.2;
  const x=e.clientX-rect.left-size/2;
  const y=e.clientY-rect.top-size/2;
  ripple.style.cssText=`width:${size}px;height:${size}px;left:${x}px;top:${y}px`;
  btn.appendChild(ripple);
  setTimeout(()=>ripple.remove(),600);
}

// ===================== TOAST =====================
var _toastTimer=null;
function showToast(msg){
  const t=document.getElementById('toast');
  const msgEl=document.getElementById('toast-msg');
  if(!t||!msgEl)return;
  if(_toastTimer){clearTimeout(_toastTimer);_toastTimer=null;}
  // Determine icon: use ✕ for destructive actions, ✓ for saves
  const isDelete=(msg||'').toLowerCase().match(/delet|remov|reset|clear/);
  const checkEl=document.getElementById('toast-check');
  if(checkEl){
    checkEl.textContent=isDelete?'✕':'✓';
    checkEl.style.background=isDelete?'var(--terra)':'var(--gold)';
    checkEl.style.color=isDelete?'#fff':'var(--ink)';
  }
  msgEl.textContent=msg;
  t.classList.remove('toast-out');
  t.classList.add('toast-in');
  _toastTimer=setTimeout(()=>{
    t.classList.remove('toast-in');
    t.classList.add('toast-out');
    setTimeout(()=>{t.classList.remove('toast-out');},260);
  },2200);
}

